// Linux open-flag constants (used by open / openat / fcntl translation).
//
// Source of truth: `include/uapi/asm-generic/fcntl.h`.  Only the bits the
// translator interprets explicitly are listed.
// ---------------------------------------------------------------------------

/// Linux `O_*` flag bits (subset interpreted by this layer).
pub mod oflags {
    pub const O_ACCMODE: u32 = 0o0003;
    pub const O_RDONLY: u32 = 0o0000;
    pub const O_WRONLY: u32 = 0o0001;
    pub const O_RDWR: u32 = 0o0002;
    pub const O_CREAT: u32 = 0o100;
    pub const O_EXCL: u32 = 0o200;
    pub const O_TRUNC: u32 = 0o1000;
    pub const O_APPEND: u32 = 0o2000;
    pub const O_NONBLOCK: u32 = 0o4000;
    pub const O_DIRECTORY: u32 = 0o200_000;
    pub const O_CLOEXEC: u32 = 0o2_000_000;
}

/// Linux `fcntl` command numbers (subset).
pub mod fcntl_cmd {
    pub const F_DUPFD: u32 = 0;
    pub const F_GETFD: u32 = 1;
    pub const F_SETFD: u32 = 2;
    pub const F_GETFL: u32 = 3;
    pub const F_SETFL: u32 = 4;
    /// Set the pid (positive) / pgid (negative) that receives `SIGIO`
    /// when the fd signals readiness for async I/O.  0 clears the
    /// delivery target.
    pub const F_SETOWN: u32 = 8;
    /// Read the value stored by [`F_SETOWN`].
    pub const F_GETOWN: u32 = 9;
    /// Set the signal number delivered in lieu of `SIGIO` (0 means
    /// "use SIGIO"; otherwise must be in `1..=64`).
    pub const F_SETSIG: u32 = 10;
    /// Read the value stored by [`F_SETSIG`].
    pub const F_GETSIG: u32 = 11;
    /// Like [`F_SETOWN`] but takes a `struct f_owner_ex` so the caller
    /// can address a specific thread / process / process group instead
    /// of the implicit "positive = pid, negative = pgrp, 0 = clear"
    /// scheme.  Used by libuv / glibc when wiring SIGIO to a
    /// specific worker thread.
    pub const F_SETOWN_EX: u32 = 15;
    /// Read the value stored by [`F_SETOWN_EX`] into a
    /// `struct f_owner_ex`.
    pub const F_GETOWN_EX: u32 = 16;
    /// Install a file lease (`F_RDLCK` / `F_WRLCK`) or release one
    /// (`F_UNLCK`) on an open fd.  Used by Samba (CIFS oplocks), NFSv4
    /// servers, and database lock daemons that need a "tell me if
    /// anyone else opens this file" notification.
    pub const F_SETLEASE: u32 = 1024;
    /// Read the type of lease currently held on an fd (or `F_UNLCK`
    /// if none).
    pub const F_GETLEASE: u32 = 1025;
    pub const F_DUPFD_CLOEXEC: u32 = 1030;
    /// Linux 6.10+: query whether `fd` and `arg` (also an fd) refer
    /// to the same open file description.  Returns 1 if same, 0 if
    /// different, EBADF if either fd is invalid.  io_uring fd-table
    /// validation, runtime introspection (Tracy, dtrace-equivalents),
    /// and language runtimes that share file handles across worker
    /// threads probe this to detect dup'd fds without resorting to
    /// /proc/self/fdinfo parsing.
    pub const F_DUPFD_QUERY: u32 = 1027;

    /// Per-open-fd write-life hint (`RWH_WRITE_LIFE_*`).  rocksdb /
    /// postgres / leveldb use this to advise the I/O layer of the
    /// expected lifetime of data written via this fd so SSD
    /// wear-leveling can group writes by lifetime.
    pub const F_GET_RW_HINT: u32 = 1035;
    /// Counterpart write that updates the per-open-fd hint.
    pub const F_SET_RW_HINT: u32 = 1036;
    /// Per-file write-life hint (shared across all open fds of the
    /// same inode).
    pub const F_GET_FILE_RW_HINT: u32 = 1037;
    /// Counterpart write that updates the per-file hint.
    pub const F_SET_FILE_RW_HINT: u32 = 1038;

    /// `RWH_WRITE_LIFE_*` values for F_*_RW_HINT.  Numeric values
    /// match `<linux/fcntl.h>` and the in-kernel `WRITE_LIFE_*`
    /// enum used by the block I/O layer for SSD wear-leveling.
    pub mod write_hint {
        /// No hint set — kernel uses default placement.
        pub const RWH_WRITE_LIFE_NOT_SET: u64 = 0;
        /// Caller has no hint to give.
        pub const RWH_WRITE_LIFE_NONE: u64 = 1;
        /// Short-lived data (temp files, hot caches).
        pub const RWH_WRITE_LIFE_SHORT: u64 = 2;
        /// Medium-lived data.
        pub const RWH_WRITE_LIFE_MEDIUM: u64 = 3;
        /// Long-lived data.
        pub const RWH_WRITE_LIFE_LONG: u64 = 4;
        /// Extreme-lifetime data (almost never rewritten).
        pub const RWH_WRITE_LIFE_EXTREME: u64 = 5;
        /// Inclusive upper bound on legal hint values.  Anything
        /// above triggers EINVAL in F_SET_*.
        pub const MAX: u64 = RWH_WRITE_LIFE_EXTREME;
    }

    /// `arg` values for [`F_SETLEASE`] and return values for
    /// [`F_GETLEASE`].  These constants are shared across Linux's
    /// lease and advisory-lock APIs (`struct flock::l_type`) — see
    /// `<bits/fcntl.h>`.
    pub mod lease_type {
        /// Read lease — notify on conflicting open-for-write.
        pub const F_RDLCK: i32 = 0;
        /// Write lease — notify on any conflicting open.
        pub const F_WRLCK: i32 = 1;
        /// Release a held lease (or report no lease held).
        pub const F_UNLCK: i32 = 2;
    }
    /// Resize the kernel-side ring buffer behind a pipe fd.  Linux
    /// validates the size against the page minimum and
    /// `/proc/sys/fs/pipe-max-size`; we mirror those bounds (see
    /// [`crate::ipc::pipe::MIN_PIPE_BUFFER_CAPACITY`] /
    /// [`crate::ipc::pipe::MAX_PIPE_BUFFER_CAPACITY`]).  Returns the
    /// new capacity on success.
    pub const F_SETPIPE_SZ: u32 = 1031;
    /// Read the current pipe buffer capacity in bytes.  Linux
    /// returns the buffer size of the pipe behind the fd; we
    /// return the underlying `Vec` length, which is what
    /// `F_SETPIPE_SZ` set (or `DEFAULT_BUFFER_CAPACITY` for a
    /// fresh pipe).
    pub const F_GETPIPE_SZ: u32 = 1032;

    /// `arg` is a bitmask of `F_SEAL_*` flags to OR into the memfd's
    /// active seal mask.  Linux numbers it 1033 in `<linux/fcntl.h>`.
    /// Only valid on memfd fds; non-memfd fds return EINVAL.  The
    /// memfd must have been created with `MFD_ALLOW_SEALING` or the
    /// add returns EPERM (the implicit `F_SEAL_SEAL` blocks adds).
    pub const F_ADD_SEALS: u32 = 1033;
    /// Read the current `F_SEAL_*` bitmask from a memfd.  Returns the
    /// mask as the syscall return value (Linux passes it back through
    /// the standard fcntl integer return path).
    pub const F_GET_SEALS: u32 = 1034;

    /// POSIX advisory record-lock commands.  All three take a
    /// `struct flock *` in `arg` and operate on a half-open byte
    /// range of the file behind the fd.  Linux numbers them 5/6/7
    /// in `<asm-generic/fcntl.h>` (these are the architecture-neutral
    /// values used on x86_64; the `_64` aliases share the same
    /// numbers when off_t is already 64-bit).
    ///
    /// In our kernel only one process can hold a Linux fd table at
    /// a time (no cross-process visibility yet), so no other holder
    /// can conflict.  `F_SETLK` / `F_SETLKW` always grant; `F_GETLK`
    /// always reports `F_UNLCK` ("no conflict").  Callers that use
    /// flock-style locking on /var/run pidfiles, sqlite WAL locking,
    /// and Postgres backend startup all proceed without modification.
    pub const F_GETLK: u32 = 5;
    pub const F_SETLK: u32 = 6;
    pub const F_SETLKW: u32 = 7;

    /// Open File Description (OFD) lock variants — Linux 3.15+.
    /// Same `struct flock` shape but locks are owned by the open
    /// file description rather than the (pid, inode) pair, which
    /// makes them inheritable across fork/dup and safe to use
    /// between threads in the same process.  Numbers come from
    /// `<linux/fcntl.h>`.  The OFD ABI requires `l_pid == 0` on
    /// input; we enforce that and otherwise behave identically to
    /// the POSIX variants (always granted / always no-conflict).
    pub const F_OFD_GETLK: u32 = 36;
    pub const F_OFD_SETLK: u32 = 37;
    pub const F_OFD_SETLKW: u32 = 38;

    /// `type` field values for `struct f_owner_ex` used by
    /// `F_GETOWN_EX` / `F_SETOWN_EX`.  Numeric values match Linux's
    /// `<bits/fcntl.h>`.
    pub mod owner_type {
        /// Address a single thread (TID).  In our kernel TID == PID
        /// because we don't yet expose intra-process thread IDs;
        /// translation falls back to the PID storage.
        pub const F_OWNER_TID: i32 = 0;
        /// Address an entire process (PID).
        pub const F_OWNER_PID: i32 = 1;
        /// Address a process group (PGID).  Stored as a negative
        /// value in the existing PCB owner slot to share encoding
        /// with `F_SETOWN`.
        pub const F_OWNER_PGRP: i32 = 2;
    }
}

/// Linux `AT_FDCWD` — special "current working directory" base fd for
/// the `*at` family of syscalls.  `AT_FDCWD` resolves a relative path
/// against the caller's cwd; a real directory `dirfd` is also supported
/// (see [`resolve_at_path`] / [`sys_openat`]): the dirfd is resolved to
/// its VFS path and the relative path is appended.  An absolute path
/// ignores `dirfd` per POSIX.  Fidelity note: dirfd resolution is
/// path-reconstruction, not true inode anchoring, so a directory renamed
/// between the `open` and the `*at` call resolves against the new name.
pub const AT_FDCWD: i32 = -100;

