    /// `SO_BROADCAST` — permit sending to a broadcast address (a `bool`/`int`).
    pub const SO_BROADCAST: i32 = 6;
    /// `SO_SNDBUF` — send-buffer size hint (an `int`).
    pub const SO_SNDBUF: i32 = 7;
    /// `SO_RCVBUF` — receive-buffer size hint (an `int`).
