/// `IPPROTO_TCP`-level option names (Linux `TCP_*`).
mod tcpopt {
    /// `TCP_NODELAY` — disable Nagle (a `bool`/`int`). Our daemon never coalesces
    /// (it sends each segment immediately), so it is effectively always on.
    pub const TCP_NODELAY: i32 = 1;
}

/// `MSG_*` per-call flags for `send(2)`/`sendto(2)`/`recv(2)`/`recvfrom(2)`
/// (the `flags` argument, arg3).  Values mirror Linux `include/linux/socket.h`.
///
/// `MSG_DONTWAIT`, `MSG_WAITALL`, and `MSG_PEEK` change behaviour; the rest are
/// silently ignored, which is already correct for our daemon-backed streams —
/// notably `MSG_NOSIGNAL` (0x4000) is a no-op because we never raise `SIGPIPE`
/// (a broken pipe surfaces as the `EPIPE` return value instead).
mod msgflags {
    /// Peek at received data without consuming it: buffered bytes are copied to
    /// the caller but remain queued, so a subsequent receive returns the same
    /// data.  Honoured on daemon-backed stream receives via the ring's
    /// `RECV_PEEK` flag.
    pub const MSG_PEEK: u32 = 0x2;
    /// Per-call non-blocking override.  Behaves like the fd's `O_NONBLOCK` was
    /// set for this one call, regardless of the fd's actual status flags: a
    /// receive with no data ready, or a send whose window is full, returns
    /// `EAGAIN` instead of blocking on the daemon.
    pub const MSG_DONTWAIT: u32 = 0x40;
    /// Block a receive until the *full* requested length has been read (rather
    /// than returning as soon as any data is available).  Terminates early only
    /// on EOF (peer closed), an error, or when the socket is non-blocking
    /// (`O_NONBLOCK`/`MSG_DONTWAIT`), in which case it degrades to a single-shot
    /// receive of whatever is available.
    pub const MSG_WAITALL: u32 = 0x100;
}

// ---------------------------------------------------------------------------
// SA_RESTART — kernel-internal syscall-restart sentinels and decision logic
// ---------------------------------------------------------------------------

/// Kernel-internal "should this syscall be restarted?" sentinels.
///
/// Mirrors Linux `include/linux/errno.h` (values 512–516).  An interruptible
/// blocking syscall that is woken by a pending signal returns one of these
/// (in negated `-VALUE` form, like any `-errno`) **instead of** `-EINTR`.
/// The signal-delivery checkpoint then decides — based on whether a handler
/// runs and that handler's `SA_RESTART` flag — whether to transparently
/// restart the syscall (rewind `%rip` to the `syscall` instruction and reload
/// `%rax` with the original syscall number) or to convert the sentinel to the
/// user-visible `-EINTR`.
///
/// These values MUST NEVER reach userspace: every path that returns a value to
/// ring 3 ([`crate::syscall::entry`]) runs them through [`restart_action`] and
/// either restarts or substitutes `-EINTR`.  [`leaked_sentinel_to_eintr`] is
/// the final backstop.
pub mod restart {
    use super::errno;

    /// Restart iff the interrupting handler has `SA_RESTART` (the common case
    /// for `read`/`write`/`wait4`/`futex` on slow objects).
    pub const ERESTARTSYS: i64 = 512;
    /// Always restart, regardless of `SA_RESTART` (e.g. a stop signal that was
    /// just a job-control bounce — the syscall must not observe EINTR).
    pub const ERESTARTNOINTR: i64 = 513;
    /// Restart only when **no** handler runs; if a handler runs, give EINTR
    /// (used where restarting after a user handler would be wrong, e.g.
    /// `accept`-class calls in some configurations).
    pub const ERESTARTNOHAND: i64 = 514;
    /// Restart via the `restart_syscall(2)` trampoline using a saved
    /// `restart_block` (e.g. `nanosleep`, which must resume with the
    /// *remaining* time, not from scratch).
    pub const ERESTART_RESTARTBLOCK: i64 = 516;

    /// The `syscall` instruction is two bytes (`0F 05`); the saved user RIP
    /// points just past it, so a restart rewinds RIP by this amount to
    /// re-execute the instruction.
    pub const SYSCALL_INSN_LEN: u64 = 2;

    /// Is `ret` (a raw syscall return value, normally negative `-errno`) one of
    /// the restart sentinels?  Accepts either sign so callers don't have to
    /// normalise first.
    #[must_use]
    pub fn is_sentinel(ret: i64) -> bool {
        matches!(
            ret.unsigned_abs() as i64,
            ERESTARTSYS | ERESTARTNOINTR | ERESTARTNOHAND | ERESTART_RESTARTBLOCK
        )
    }

    /// The positive sentinel magnitude of `ret`, or `None` if `ret` is not a
    /// restart sentinel.
    #[must_use]
    pub fn sentinel_magnitude(ret: i64) -> Option<i64> {
        let m = ret.unsigned_abs() as i64;
        if is_sentinel(m) { Some(m) } else { None }
    }

    /// What the delivery checkpoint should do with a restart sentinel.
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub enum RestartAction {
        /// Re-execute the original syscall (rewind RIP, reload RAX = nr).
        Restart,
        /// Re-execute via the `restart_syscall` trampoline (RAX = nr_restart).
        RestartBlock,
        /// Do not restart; the user sees `-EINTR`.
        Eintr,
    }

    /// Decide the restart action, mirroring Linux `handle_signal()` /
    /// `do_signal()` (`arch/x86/kernel/signal.c`).
    ///
    /// * `sentinel` — the positive sentinel magnitude (512/513/514/516).
    /// * `has_handler` — a userspace handler is about to run for the signal.
    /// * `sa_restart` — that handler's `SA_RESTART` flag (irrelevant when
    ///   `has_handler` is false).
    #[must_use]
    pub fn restart_action(sentinel: i64, has_handler: bool, sa_restart: bool) -> RestartAction {
        match sentinel {
            // Unconditional restart.
            ERESTARTNOINTR => RestartAction::Restart,
            // restart_block: only the no-handler case resumes (with the saved
            // block); a handler turns it into EINTR.
            ERESTART_RESTARTBLOCK => {
                if has_handler {
                    RestartAction::Eintr
                } else {
                    RestartAction::RestartBlock
                }
            }
            // NOHAND: restart only when no handler ran.
            ERESTARTNOHAND => {
                if has_handler {
                    RestartAction::Eintr
                } else {
                    RestartAction::Restart
                }
            }
            // ERESTARTSYS (and any unexpected value, treated conservatively as
            // ERESTARTSYS): restart iff SA_RESTART, or unconditionally when no
            // handler runs.
            _ => {
                if has_handler {
                    if sa_restart {
                        RestartAction::Restart
                    } else {
                        RestartAction::Eintr
                    }
                } else {
                    RestartAction::Restart
                }
            }
        }
    }

    /// Final backstop: if `ret` is a restart sentinel that somehow reached a
    /// return-to-user path without being resolved, substitute `-EINTR` so the
    /// internal value can never leak to ring 3.  Non-sentinel values pass
    /// through unchanged.
    #[must_use]
    pub fn leaked_sentinel_to_eintr(ret: i64) -> i64 {
        if is_sentinel(ret) {
            -i64::from(errno::EINTR)
        } else {
            ret
        }
    }

    /// Build the in-kernel return value for an interrupted blocking syscall that
    /// should participate in `SA_RESTART` semantics.  `sentinel` is one of the
    /// `ERESTART*` constants in this module; the result carries it in negated
    /// `-VALUE` form, exactly like any `-errno`, so the signal-delivery
    /// checkpoint ([`build_linux_rt_frame`] for the handler case,
    /// [`super::resolve_syscall_restart`] for the no-handler case) can resolve
    /// it into either a restart or a user-visible `-EINTR`.  It is never
    /// returned directly to ring 3 — the backstops above guarantee that.
    #[must_use]
    pub const fn restart_result(sentinel: i64) -> super::SyscallResult {
        super::SyscallResult::ok(-sentinel)
    }
}

/// Per-task saved `restart_block` for syscalls that resume via
/// `restart_syscall(2)` — currently `nanosleep` / `clock_nanosleep`.
///
/// Linux keeps this in `task_struct.restart_block`; we key a small global
/// registry by task id.  Only the `ERESTART_RESTARTBLOCK` no-handler path
/// populates it (an interrupted `nanosleep` saves the remaining deadline);
/// [`sys_restart_syscall`] then consumes it exactly once via [`restart_block::take`].
/// A direct userspace `restart_syscall` with nothing saved gets `-EINTR`,
/// matching Linux's `do_no_restart_syscall`.
pub mod restart_block {
    use crate::sched::task::TaskId;
    use alloc::collections::BTreeMap;
    use crate::sync::PreemptSpinMutex as Mutex;

    /// A saved `nanosleep`-family resume: the absolute hrtimer-clock deadline
    /// to sleep until, and the user `rem` pointer (0 = none) to update if the
    /// resumed sleep is interrupted again.
    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    pub struct NanosleepBlock {
        /// Absolute deadline on the `hrtimer::now_ns()` monotonic clock.
        pub deadline_ns: u64,
        /// User pointer to a `struct timespec` for the remaining time, or 0.
        pub rem_ptr: u64,
    }

    static BLOCKS: Mutex<BTreeMap<TaskId, NanosleepBlock>> = Mutex::new(BTreeMap::new());

    /// Save (overwriting) the calling task's nanosleep restart block.
    pub fn save_nanosleep(task: TaskId, block: NanosleepBlock) {
        BLOCKS.lock().insert(task, block);
    }

    /// Take (remove and return) the task's saved restart block, if any.
    #[must_use]
    pub fn take(task: TaskId) -> Option<NanosleepBlock> {
        BLOCKS.lock().remove(&task)
    }

    /// Drop any saved restart block for a task without consuming it as a
    /// resume (e.g. when the task makes an unrelated blocking syscall, or on
    /// exit), so a later stray `restart_syscall` can't replay a stale sleep.
    pub fn clear(task: TaskId) {
        BLOCKS.lock().remove(&task);
    }
}

/// Resolve a restart sentinel at the **no-handler** return-to-user checkpoint.
///
/// Called from [`crate::syscall::entry::syscall_handler_inner`] after
/// `deliver_pending_signal` returned `false` (no userspace handler frame was
/// built — either nothing was deliverable, or every pending signal was ignored
/// or had a non-fatal default).
///
/// If `ret` is a [`restart`] sentinel this is the "no handler ran" case, where
/// Linux restarts the syscall unconditionally:
///
///   * `ERESTARTSYS` / `ERESTARTNOINTR` / `ERESTARTNOHAND` → restart the
///     original syscall.  We rewind `frame.user_rip` to the `syscall`
///     instruction and return the original syscall number so the SYSRET path
///     (which reloads the saved argument registers from the frame) re-executes
///     it.
///   * `ERESTART_RESTARTBLOCK` → restart via the `restart_syscall(2)`
///     trampoline: same RIP rewind, but RAX is set to `nr::RESTART_SYSCALL` so
///     the resumed call consults the saved `restart_block` (e.g. `nanosleep`
///     resuming with the remaining time).
///
/// A non-sentinel value is returned unchanged.  A sentinel is **never**
/// returned to userspace.
#[must_use]
pub fn resolve_syscall_restart(
    frame: &mut crate::syscall::entry::SyscallFrame,
    ret: i64,
) -> i64 {
    let Some(sentinel) = restart::sentinel_magnitude(ret) else {
        return ret;
    };
    match restart::restart_action(sentinel, false, false) {
        restart::RestartAction::Restart => {
            frame.user_rip = frame.user_rip.wrapping_sub(restart::SYSCALL_INSN_LEN);
            #[allow(clippy::cast_possible_wrap)]
            {
                frame.syscall_nr as i64
            }
        }
        restart::RestartAction::RestartBlock => {
            frame.user_rip = frame.user_rip.wrapping_sub(restart::SYSCALL_INSN_LEN);
            #[allow(clippy::cast_possible_wrap)]
            {
                nr::RESTART_SYSCALL as i64
            }
        }
        // restart_action never yields Eintr when has_handler == false, but stay
        // total: convert to EINTR rather than ever leaking the sentinel.
        restart::RestartAction::Eintr => -i64::from(errno::EINTR),
    }
}

// ---------------------------------------------------------------------------
// Native KernelError → Linux errno
// ---------------------------------------------------------------------------

/// Translate a native [`KernelError`] to the corresponding Linux errno
/// (positive value).  Callers typically want `-(linux_errno_for(e) as i64)`
/// as the syscall return value.
///
/// When in doubt this returns `EINVAL` — that's the Linux convention for
/// "the kernel rejected the call as malformed" and matches what Linux
/// itself does for unknown-cause failures.
#[must_use]
pub const fn linux_errno_for(e: KernelError) -> i32 {
    match e {
        KernelError::InternalError => errno::EIO,
        KernelError::NotSupported => errno::ENOSYS,
        KernelError::InvalidArgument => errno::EINVAL,
        KernelError::WouldBlock => errno::EAGAIN,
        KernelError::Cancelled => errno::ECANCELED,
        KernelError::TimedOut => errno::ETIMEDOUT,
        KernelError::Deadlock => errno::EDEADLK,
        KernelError::Interrupted => errno::EINTR,
        KernelError::OutOfMemory => errno::ENOMEM,
        KernelError::InvalidAddress => errno::EFAULT,
        KernelError::PageFault => errno::EFAULT,
        KernelError::BadAlignment => errno::EINVAL,
        KernelError::NoSuchProcess => errno::ESRCH,
        KernelError::InvalidExecutable => errno::ENOEXEC,
        KernelError::ProcessExited => errno::ECHILD,
        KernelError::NoChildProcess => errno::ECHILD,
        KernelError::ChannelClosed => errno::EPIPE,
        KernelError::ChannelFull => errno::EAGAIN,
        KernelError::MessageTooLarge => errno::E2BIG,
        KernelError::Overflow => errno::EOVERFLOW,
        KernelError::ResourceExhausted => errno::ENFILE,
        KernelError::PermissionDenied => errno::EACCES,
        KernelError::InvalidCapability => errno::EPERM,
        KernelError::NotFound => errno::ENOENT,
        KernelError::AlreadyExists => errno::EEXIST,
        KernelError::NotADirectory => errno::ENOTDIR,
        KernelError::IsADirectory => errno::EISDIR,
        KernelError::DiskFull => errno::ENOSPC,
        KernelError::InvalidHandle => errno::EBADF,
        KernelError::TooManyLinks => errno::ELOOP,
        KernelError::NotEmpty => errno::ENOTEMPTY,
        KernelError::CorruptedData => errno::EIO,
        KernelError::ReadOnlyFilesystem => errno::EROFS,
        KernelError::TooManyOpenFiles => errno::EMFILE,
        KernelError::FileTooLarge => errno::EFBIG,
        KernelError::CrossDevice => errno::EXDEV,
        KernelError::IoError => errno::EIO,
        KernelError::NoSuchDevice => errno::ENODEV,
        KernelError::DeviceBusy => errno::EBUSY,
        KernelError::ConnectionRefused => errno::ECONNREFUSED,
        KernelError::NotConnected => errno::ENOTCONN,
        KernelError::InProgress => errno::EINPROGRESS,
        KernelError::ConnectAlready => errno::EALREADY,
        KernelError::BrokenPipe => errno::EPIPE,
        KernelError::AddrInUse => errno::EADDRINUSE,
        KernelError::MsgSize => errno::EMSGSIZE,
    }
}

/// Convert a native [`SyscallResult`] to the Linux ABI form.
///
/// On success (`value >= 0`), the value is passed through unchanged.
/// On error (`value < 0`), the native error code is interpreted as a
/// [`KernelError`] and remapped to `-(linux_errno_for(e) as i64)`.
#[must_use]
pub fn linux_from_native(res: SyscallResult) -> SyscallResult {
    if res.value >= 0 {
        return res;
    }
    // Native error encoding: the value is a signed kernel-error code
    // (negative i32 widened to i64).  Recover the original variant from
    // the code, then map it to a Linux errno.
    #[allow(clippy::cast_possible_truncation)]
    let code = res.value as i32;
    let errno_val = match kernel_error_from_code(code) {
        Some(e) => linux_errno_for(e),
        None => errno::EINVAL,
    };
    SyscallResult::ok(-i64::from(errno_val))
}

/// Translate a *native* result from a **slow** I/O object (pipe/FIFO,
/// socket, tty — anything with no inherent timeout) into the Linux ABI
/// form, honouring SA_RESTART.
///
/// These objects block indefinitely waiting for the peer, so a signal
/// that interrupts the wait is restartable: per Linux's taxonomy, an
/// interrupted `read`/`write` on a slow object returns the
/// `ERESTARTSYS` restart sentinel (which the signal-delivery checkpoint
/// turns into either a transparent restart when the handler has
/// `SA_RESTART`, or `-EINTR` otherwise).  The blocking pipe primitives
/// report this interruption as [`KernelError::Interrupted`] (native code
/// `-8`); we recognise that one code here and substitute the sentinel.
///
/// Every other result — success, `EOF`, or any real error — passes
/// straight through [`linux_from_native`].  In particular a *timed* pipe
/// wait that is interrupted must NOT be restarted (restarting would reset
/// the relative timeout from scratch); those call sites map `Interrupted`
/// to `-EINTR` directly via [`linux_from_native`] and never reach here.
#[must_use]
pub fn linux_from_slow_io(res: SyscallResult) -> SyscallResult {
    // Native `Interrupted` (-8): a deliverable signal woke the blocking
    // wait before any byte was transferred.  Surface the restart sentinel.
    if res.value == KernelError::Interrupted as i64 {
        return restart::restart_result(restart::ERESTARTSYS);
    }
    linux_from_native(res)
}

/// Translate a *native* futex-wait result into the Linux `FUTEX_WAIT`
/// ABI return convention.
///
/// The native futex-wait handlers ([`handlers::sys_futex_wait`],
/// [`handlers::sys_futex_wait_bitset`] and their timed variants) report
/// success with the Slate convention:
///   * `Ok(1)` — the caller actually blocked and was woken by a matching
///     `FUTEX_WAKE`.
///   * `Ok(0)` — the futex word did **not** equal the expected value at
///     entry, so the wait returned immediately without blocking.
///   * `Err(TimedOut)` — the (relative) deadline elapsed while blocked.
///   * `Err(_)` — a real error (e.g. `InvalidAddress` → `EFAULT`).
///
/// Linux's `futex(FUTEX_WAIT*)` instead returns `0` when woken (or
/// spuriously), `-EAGAIN` when the value did not match, `-ETIMEDOUT` on
/// timeout, and `-EFAULT`/etc. on error.  Crucially, glibc's
/// `futex_wait`/`lll_futex_wait` wrappers treat **any** other return
/// value — notably a positive `1` — as `futex_fatal_error()` ("The futex
/// facility returned an unexpected error code.") and abort the process.
/// pthread_join's `lll_wait_tid` loop hits exactly this path: when the
/// joined thread exits, `CLONE_CHILD_CLEARTID` zeroes the tid word and
/// wakes the joiner, whose `FUTEX_WAIT_BITSET` must return `0`, not `1`.
///
/// This is the same mapping `sys_futex_waitv` applies inline; the three
/// classic wait ops (`FUTEX_WAIT`, `FUTEX_WAIT_BITSET`, `futex2_wait`)
/// route through here so the convention lives in one place.
fn linux_from_futex_wait(res: SyscallResult) -> SyscallResult {
    // An interrupted indefinite FUTEX_WAIT is reported by the handler as an
    // `ERESTART*` restart sentinel (negated, e.g. `-512`).  That value must
    // reach the signal-delivery checkpoint untouched — it must NOT be fed to
    // `linux_from_native`, where `-512` collides with `KernelError::CrossDevice`
    // and would be mis-mapped to `EXDEV`.  Pass any restart sentinel through.
    if restart::is_sentinel(res.value) {
        return res;
    }
    match res.value {
        // Blocked and woken (or spurious wake) — Linux success.
        1 => SyscallResult::ok(0),
        // Value mismatch at entry — Linux reports EAGAIN.
        0 => linux_err(errno::EAGAIN),
        // Negative native error code (incl. TimedOut → ETIMEDOUT).
        _ => linux_from_native(res),
    }
}

/// Recover a [`KernelError`] from its stable integer code.
///
/// This is the inverse of `KernelError::code()`.  Returns `None` if
/// the code does not name any known variant.
#[must_use]
pub const fn kernel_error_from_code(code: i32) -> Option<KernelError> {
    match code {
        -1 => Some(KernelError::InternalError),
        -2 => Some(KernelError::NotSupported),
        -3 => Some(KernelError::InvalidArgument),
        -4 => Some(KernelError::WouldBlock),
        -5 => Some(KernelError::Cancelled),
        -6 => Some(KernelError::TimedOut),
        -7 => Some(KernelError::Deadlock),
        -8 => Some(KernelError::Interrupted),
        -100 => Some(KernelError::OutOfMemory),
        -101 => Some(KernelError::InvalidAddress),
        -102 => Some(KernelError::PageFault),
        -103 => Some(KernelError::BadAlignment),
        -200 => Some(KernelError::NoSuchProcess),
        -201 => Some(KernelError::InvalidExecutable),
        -202 => Some(KernelError::ProcessExited),
        -203 => Some(KernelError::NoChildProcess),
        -300 => Some(KernelError::ChannelClosed),
        -301 => Some(KernelError::ChannelFull),
        -302 => Some(KernelError::MessageTooLarge),
        -303 => Some(KernelError::Overflow),
        -304 => Some(KernelError::ResourceExhausted),
        -400 => Some(KernelError::PermissionDenied),
        -401 => Some(KernelError::InvalidCapability),
        -500 => Some(KernelError::NotFound),
        -501 => Some(KernelError::AlreadyExists),
        -502 => Some(KernelError::NotADirectory),
        -503 => Some(KernelError::IsADirectory),
        -504 => Some(KernelError::DiskFull),
        -505 => Some(KernelError::InvalidHandle),
        -506 => Some(KernelError::TooManyLinks),
        -507 => Some(KernelError::NotEmpty),
        -508 => Some(KernelError::CorruptedData),
        -509 => Some(KernelError::ReadOnlyFilesystem),
        -510 => Some(KernelError::TooManyOpenFiles),
        -511 => Some(KernelError::FileTooLarge),
        -512 => Some(KernelError::CrossDevice),
        -600 => Some(KernelError::IoError),
        -601 => Some(KernelError::NoSuchDevice),
        -602 => Some(KernelError::DeviceBusy),
        _ => None,
    }
}

/// Build a Linux-style error result with the given errno.
#[must_use]
pub const fn linux_err(errno_val: i32) -> SyscallResult {
    SyscallResult::ok(-(errno_val as i64))
}

// ---------------------------------------------------------------------------
// Linux frame-modifying constants (clone flags)
// ---------------------------------------------------------------------------

/// Subset of Linux `CLONE_*` flag bits we explicitly recognise.  Bits
/// 0..7 of `flags` carry the termination signal (`CSIGNAL`); the rest
/// are the actual sharing-control bits.
///
/// Source: `include/uapi/linux/sched.h`.
pub mod clone_flags {
    pub const CSIGNAL: u64 = 0x0000_00ff;
    pub const CLONE_NEWTIME: u64 = 0x0000_0080;
    pub const CLONE_VM: u64 = 0x0000_0100;
    pub const CLONE_FS: u64 = 0x0000_0200;
    pub const CLONE_FILES: u64 = 0x0000_0400;
    pub const CLONE_SIGHAND: u64 = 0x0000_0800;
    /// CLONE_PIDFD — allocate a pidfd referring to the new task.
    /// clone3-only (overloads the parent_tid slot in clone(2)).
    pub const CLONE_PIDFD: u64 = 0x0000_1000;
    pub const CLONE_PTRACE: u64 = 0x0000_2000;
    pub const CLONE_VFORK: u64 = 0x0000_4000;
    pub const CLONE_PARENT: u64 = 0x0000_8000;
    pub const CLONE_THREAD: u64 = 0x0001_0000;
    pub const CLONE_NEWNS: u64 = 0x0002_0000;
    pub const CLONE_SYSVSEM: u64 = 0x0004_0000;
    pub const CLONE_SETTLS: u64 = 0x0008_0000;
    pub const CLONE_PARENT_SETTID: u64 = 0x0010_0000;
    pub const CLONE_CHILD_CLEARTID: u64 = 0x0020_0000;
    pub const CLONE_DETACHED: u64 = 0x0040_0000;
    pub const CLONE_UNTRACED: u64 = 0x0080_0000;
    pub const CLONE_CHILD_SETTID: u64 = 0x0100_0000;
    pub const CLONE_NEWCGROUP: u64 = 0x0200_0000;
    pub const CLONE_NEWUTS: u64 = 0x0400_0000;
    pub const CLONE_NEWIPC: u64 = 0x0800_0000;
    pub const CLONE_NEWUSER: u64 = 0x1000_0000;
    pub const CLONE_NEWPID: u64 = 0x2000_0000;
    pub const CLONE_NEWNET: u64 = 0x4000_0000;
    pub const CLONE_IO: u64 = 0x8000_0000;
    /// CLONE_CLEAR_SIGHAND — reset signal handlers in the child.
    /// clone3-only, bit 32.
    pub const CLONE_CLEAR_SIGHAND: u64 = 0x1_0000_0000;
    /// CLONE_INTO_CGROUP — place the new task in the cgroup whose fd
    /// is given in `clone_args.cgroup`.  clone3-only, bit 33.
    pub const CLONE_INTO_CGROUP: u64 = 0x2_0000_0000;
    /// SIGCHLD is the conventional CSIGNAL byte for fork-equivalent
    /// `clone()` calls.
    pub const SIGCHLD: u64 = 17;
}

// ---------------------------------------------------------------------------
// Frame-modifying dispatch
// ---------------------------------------------------------------------------

/// Dispatch the Linux syscalls that need direct access to the saved
/// register frame (fork / vfork / clone / execve).
///
/// Returns `Some(rax)` if this function handled the syscall — the caller
/// must propagate `rax` straight back to userspace (after the usual
/// signal-delivery hook).  Returns `None` for any syscall number that
/// is not one of these frame-modifying paths; the caller then falls
/// through to the regular `dispatch_linux(nr, args)`.
///
/// This mirrors the native `syscall_handler_inner` top-of-function
/// checks for `SYS_PROCESS_EXEC` / `SYS_PROCESS_FORK` etc., but for
/// Linux-ABI processes and using Linux syscall numbers.
#[must_use]
pub fn dispatch_linux_with_frame(
    frame: &mut crate::syscall::entry::SyscallFrame,
) -> Option<i64> {
    match frame.syscall_nr {
        nr::FORK | nr::VFORK => Some(linux_fork(frame)),
        nr::CLONE => Some(linux_clone(frame)),
        nr::CLONE3 => Some(linux_clone3(frame)),
        nr::EXECVE => Some(linux_execve(frame)),
        nr::EXECVEAT => Some(linux_execveat(frame)),
        nr::RT_SIGRETURN => Some(linux_rt_sigreturn(frame)),
        _ => None,
    }
}

/// Linux `clone3(cl_args*, size)` translation.
///
/// `clone3` (Linux 5.3+) is the modern replacement for `clone(2)`:
/// instead of passing five register arguments (flags, stack, ptid,
/// ctid, tls), the caller hands in a pointer to `struct clone_args`
/// plus its byte length.  This lets the ABI evolve by appending
/// fields without burning new syscall numbers.
///
/// `struct clone_args` (uapi `<linux/sched.h>`):
///
/// ```c
/// struct clone_args {
///     __u64 flags;        // CLONE_* bits (no CSIGNAL byte here)
///     __u64 pidfd;        // out: pidfd if CLONE_PIDFD
///     __u64 child_tid;    // CLONE_CHILD_SETTID / CLONE_CHILD_CLEARTID target
///     __u64 parent_tid;   // CLONE_PARENT_SETTID target
///     __u64 exit_signal;  // CSIGNAL byte (lives here, not OR'd into flags)
///     __u64 stack;        // child stack *base* (not top, unlike clone(2))
///     __u64 stack_size;   // child stack size; new RSP = stack + stack_size
///     __u64 tls;          // CLONE_SETTLS payload
///     /* added Linux 5.5: */
///     __u64 set_tid;      // userspace TID array (CLONE_NEWPID hierarchy)
///     __u64 set_tid_size; // number of u32 entries in set_tid
///     /* added Linux 5.7: */
///     __u64 cgroup;       // cgroup fd (used with CLONE_INTO_CGROUP)
/// };
/// ```
///
/// The size argument distinguishes ABI versions: the kernel reads
/// only as many fields as the user supplied (zero-extending the rest).
/// Three valid sizes match the three additions above:
///
///   * `CLONE_ARGS_SIZE_VER0 = 64` — original clone3 (Linux 5.3).
///   * `CLONE_ARGS_SIZE_VER1 = 80` — adds set_tid + set_tid_size.
///   * `CLONE_ARGS_SIZE_VER2 = 88` — adds cgroup.
///
/// Anything smaller than 64, or larger than `PAGE_SIZE`, or that
/// names a field we don't recognise, is rejected with EINVAL.
///
/// ## Mapping clone3 onto clone()
///
/// `clone_args.exit_signal` is OR'd into the low byte of `flags` so
/// the rest of the kernel sees the same `CSIGNAL`-byte convention
/// `clone(2)` uses.  `clone_args.stack + clone_args.stack_size` is
/// the value `clone(2)` callers would have computed in userspace
/// before invoking the syscall (Linux's clone(2) wants the stack
/// *top* in `rsi`; clone3 carries base + size separately so the
/// kernel can do the arithmetic, freeing userspace from having to
/// know which direction the stack grows).  The other four fields
/// (pidfd, child_tid, parent_tid, tls) line up with clone(2)'s
/// arg slots and forward unchanged through `linux_clone_inner`.
///
/// ## What we explicitly reject
///
/// Features beyond what `linux_clone` already supports get EINVAL
/// or ENOSYS up front so callers fall back to clone() (which they
/// must already support — glibc's `__clone3_internal` always has a
/// `__clone_wrapper` shim).
///
///   * `CLONE_PIDFD` — deferred, NOT for lack of a pidfd object
///     (`HandleKind::PidFd` / `FdEntry::pidfd` already back the working
///     `pidfd_open(2)`).  The blocker is the all-or-nothing ordering:
///     Linux's `copy_process` reserves the pidfd via `pidfd_prepare`
///     *before* the point of no return, so a full fd table or an
///     unwritable `args->pidfd` fails the whole clone with no child.
///     Our fork path creates the child first (`linux_fork`) and could
///     only install the pidfd afterwards, which inverts that invariant.
///     Doing it correctly needs a pre-fork fd-slot reservation +
///     write-validation, and — critically — its happy path can only be
///     verified from a real userspace process context (the boot
///     self-test runs in kernel context, where pidfd install returns
///     EBADF), so it needs a userspace integration-test harness first.
///     Tracked in todo.txt ("CLONE_PIDFD sibling-consistency gap").
///   * `CLONE_INTO_CGROUP` or `cgroup != 0` — no cgroup subsystem.
///   * `set_tid_size > 0` — we don't honour manual TID assignment.
///   * `CLONE_CLEAR_SIGHAND` — our signal-handler model doesn't yet
///     track per-thread handler tables independently from the PCB.
///   * Any namespace flag (`CLONE_NEWNS`, `CLONE_NEWPID`, etc.) —
///     these need a namespace subsystem (deferred per `design.txt`).
///   * `exit_signal` outside the low byte — Linux constrains this
///     to a single u8 signal number; any value > 0xFF would round
///     into the flag bits of the constructed clone() call.
fn linux_clone3(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    let translated = match validate_clone3_args(frame.arg0, frame.arg1) {
        Ok(t) => t,
        Err(e) => return -i64::from(e),
    };
    linux_clone_inner(
        translated.flags,
        translated.child_stack,
        translated.parent_tid,
        translated.child_tid,
        translated.tls,
        frame,
    )
}

/// Decoded `struct clone_args` after validation and translation to
/// `clone(2)`'s register-arg layout.
struct ClonedArgs {
    flags: u64,
    child_stack: u64,
    parent_tid: u64,
    child_tid: u64,
    tls: u64,
}

/// Validate a `clone3` `clone_args*` plus its declared size, returning
/// either the decoded arguments in `clone(2)`-shaped form or the errno
/// to fail with.  Shared between the real `linux_clone3` frame path
/// and the args-only `sys_clone3` dispatch site used by the boot
/// self-test.
fn validate_clone3_args(cl_args_ptr: u64, size: u64) -> Result<ClonedArgs, i32> {
    /// VER0 from `<linux/sched.h>` — original clone3 ABI (Linux 5.3).
    const CLONE_ARGS_SIZE_VER0: u64 = 64;
    /// Hard cap on `size`.  Linux uses `PAGE_SIZE` (4 KiB on x86); our
    /// base page is 16 KiB but a 4-KiB cap is still ample headroom for
    /// any plausible future extension of `struct clone_args`.
    const CLONE_ARGS_SIZE_MAX: u64 = 4096;

    // Gate order matches Linux's `copy_clone_args_from_user`
    // (kernel/fork.c):
    //   1. `usize > PAGE_SIZE` -> -E2BIG
    //   2. `usize < CLONE_ARGS_SIZE_VER0` -> -EINVAL
    //   3. `copy_struct_from_user(...)` -> -EFAULT on NULL/unmapped
    //
    // Pre-batch we mapped `size > MAX` to `EINVAL` and rejected NULL
    // ahead of any size check, so a probe with `(NULL, size=8192)`
    // saw `EFAULT` where Linux returns `E2BIG`, and a probe with
    // `(buf, size=8192)` saw `EINVAL` where Linux returns `E2BIG`.
    if size > CLONE_ARGS_SIZE_MAX {
        return Err(errno::E2BIG);
    }
    if size < CLONE_ARGS_SIZE_VER0 {
        return Err(errno::EINVAL);
    }
    if cl_args_ptr == 0 {
        return Err(errno::EFAULT);
    }
    // The struct must be 8-byte aligned (every field is __u64) and
    // size must itself be a multiple of 8 — Linux rounds up but we
    // reject so callers see their bug.  These are our own gates and
    // fire after Linux's documented errno discriminators above.
    if cl_args_ptr & 0x7 != 0 || size & 0x7 != 0 {
        return Err(errno::EINVAL);
    }
    if let Err(e) = crate::mm::user::validate_user_read(cl_args_ptr, size as usize) {
        return Err(linux_errno_for(e));
    }

    // Read the whole struct in one copy_from_user, then index into
    // it as a u64 array.  Any field past `size` is implicitly zero
    // (zero-extending the user struct, matching Linux's
    // `copy_struct_from_user` behaviour).
    let mut buf = [0u64; 11];
    #[allow(clippy::cast_possible_truncation)]
    let nwords = (size as usize) / 8;
    let nwords = core::cmp::min(nwords, buf.len());
    // SAFETY: validated above.  We read at most `nwords` * 8 bytes,
    // never exceeding the user-supplied size.
    let r = unsafe {
        crate::mm::user::copy_from_user(
            cl_args_ptr,
            buf.as_mut_ptr().cast::<u8>(),
            nwords * 8,
        )
    };
    if let Err(e) = r {
        return Err(linux_errno_for(e));
    }

    // Forward-compat zero check (batch 228).  Linux's
    // `copy_struct_from_user` (used inside
    // `copy_clone_args_from_user`) walks the bytes in
    // `[sizeof(struct clone_args), usize)` and returns -E2BIG if any
    // trailing byte is non-zero — the signal a userspace probe uses
    // to detect that it's passing a newer ABI field the kernel
    // doesn't recognise.  Pre-batch 228 we silently ignored bytes
    // past offset 88 (CLONE_ARGS_SIZE_VER2 = sizeof(struct
    // clone_args)).  A probe with size=96 and byte[88]=1 saw the
    // call succeed (returning the configured ENOSYS) where Linux
    // returns E2BIG.
    const CLONE_ARGS_KSIZE: u64 = 88;
    if size > CLONE_ARGS_KSIZE {
        let excess_addr = cl_args_ptr.wrapping_add(CLONE_ARGS_KSIZE);
        #[allow(clippy::cast_possible_truncation)]
        let excess_len = (size - CLONE_ARGS_KSIZE) as usize;
        if let Err(e) = crate::mm::user::validate_user_read(excess_addr, excess_len) {
            return Err(linux_errno_for(e));
        }
        let mut chunk = [0u8; 64];
        let mut off: usize = 0;
        while off < excess_len {
            let take = core::cmp::min(64, excess_len - off);
            // SAFETY: validate_user_read above confirmed `excess_len`
            // bytes are readable at `excess_addr`, and (off, take) is
            // within that range.
            if let Err(e) = unsafe {
                crate::mm::user::copy_from_user(
                    excess_addr.wrapping_add(off as u64),
                    chunk.as_mut_ptr(),
                    take,
                )
            } {
                return Err(linux_errno_for(e));
            }
            if chunk[..take].iter().any(|&b| b != 0) {
                return Err(errno::E2BIG);
            }
            off += take;
        }
    }

    let flags_user = buf[0];
    let _pidfd_out = buf[1];
    let child_tid = buf[2];
    let parent_tid = buf[3];
    let exit_signal = buf[4];
    let stack_base = buf[5];
    let stack_size = buf[6];
    let tls = buf[7];
    let set_tid = if nwords > 8 { buf[8] } else { 0 };
    let set_tid_size = if nwords > 9 { buf[9] } else { 0 };
    let cgroup = if nwords > 10 { buf[10] } else { 0 };

    // exit_signal must fit in the CSIGNAL byte; Linux rejects
    // anything else with EINVAL.
    if exit_signal & !clone_flags::CSIGNAL != 0 {
        return Err(errno::EINVAL);
    }
    // Linux semantics: passing flags that overlap the CSIGNAL byte
    // is also rejected (the byte is supposed to live in exit_signal
    // alone in clone3).
    if flags_user & clone_flags::CSIGNAL != 0 {
        return Err(errno::EINVAL);
    }

    // Reject clone3-only features we don't implement.  Linux
    // returns EINVAL for any combination it doesn't honour, and so
    // do we — that's the documented "try clone() instead" hint.
    if flags_user & clone_flags::CLONE_PIDFD != 0 {
        return Err(errno::EINVAL);
    }
    if flags_user & clone_flags::CLONE_INTO_CGROUP != 0 {
        return Err(errno::EINVAL);
    }
    // CLONE_CLEAR_SIGHAND: the child starts with every signal handler reset
    // to its default disposition.  glibc's posix_spawn(3) sets this (together
    // with CLONE_VM | CLONE_VFORK) so the spawned helper can't run an inherited
    // SIGCHLD/SIGPIPE handler before it execs.  Our per-signal dispositions
    // live in userspace and are discarded with the old address space on the
    // imminent execve (see signal::on_exec); the kernel-side trampoline is
    // likewise reset there.  For the (rare) clone3 child that does NOT exec,
    // the flag is honoured in linux_clone_inner by resetting the child's
    // kernel-side signal state after creation.  Either way we accept it
    // rather than rejecting with EINVAL.
    if set_tid_size != 0 || set_tid != 0 {
        return Err(errno::EINVAL);
    }
    if cgroup != 0 {
        return Err(errno::EINVAL);
    }

    // Reject any namespace clone.  Linux's clone3 honours these but
    // we have no namespace subsystem.
    const NAMESPACE_BITS: u64 = clone_flags::CLONE_NEWNS
        | clone_flags::CLONE_NEWCGROUP
        | clone_flags::CLONE_NEWUTS
        | clone_flags::CLONE_NEWIPC
        | clone_flags::CLONE_NEWUSER
        | clone_flags::CLONE_NEWPID
        | clone_flags::CLONE_NEWNET
        | clone_flags::CLONE_NEWTIME;
    if flags_user & NAMESPACE_BITS != 0 {
        return Err(errno::EINVAL);
    }

    // Translate stack base + size to clone(2)'s "stack top" register.
    // clone(2) wants the value of the new RSP at child entry; on x86_64
    // the stack grows down, so RSP starts at the high end of the
    // allocated region.  A NULL stack means "share the parent's stack"
    // (fork-style).  Both stack and stack_size must be zero, or both
    // non-zero — a NULL stack with non-zero size, or vice versa, is a
    // userspace bug Linux rejects with EINVAL.
    if (stack_base == 0) != (stack_size == 0) {
        return Err(errno::EINVAL);
    }
    let child_stack = if stack_base == 0 {
        0
    } else {
        match stack_base.checked_add(stack_size) {
            Some(top) => top,
            None => return Err(errno::EINVAL),
        }
    };

    // Reassemble the clone()-shaped flags word: high 56 bits are the
    // sharing/notification flags, low byte is the exit signal.
    let flags = flags_user | exit_signal;

    Ok(ClonedArgs {
        flags,
        child_stack,
        parent_tid,
        child_tid,
        tls,
    })
}

/// Set of RFLAGS bits a user `rt_sigreturn` is permitted to restore.
///
/// A signal handler can scribble arbitrary bytes into `uc.uc_mcontext`
/// before calling `rt_sigreturn`, so we must treat the restored RFLAGS
/// as fully attacker-controlled.  We keep only the arithmetic/status
/// flags plus the benign user-settable bits, then force IF=1 and the
/// reserved bit-1, and drop everything dangerous: IF-clear (would
/// disable interrupts in ring 3 — impossible anyway, but defensive),
/// IOPL (would grant I/O-port access), NT (nested-task), VM, VIF/VIP,
/// and the always-zero reserved bits.
///
/// Bits kept: CF(0) PF(2) AF(4) ZF(6) SF(7) TF(8) DF(10) OF(11) AC(18)
/// ID(21).  TF is permitted so a debugger-driven single-step survives a
/// signal round-trip, matching Linux.
const SIGRETURN_RFLAGS_USER_MASK: u64 = 0x0024_0DD5;

/// RFLAGS bits the kernel always forces on after a `rt_sigreturn`:
/// IF (interrupts enabled) + the mandatory reserved bit 1.
const SIGRETURN_RFLAGS_FORCED: u64 = 0x0000_0202;

/// Linux `rt_sigreturn(2)` translation — restores from a **Linux-shape**
/// `ucontext` built by [`build_linux_rt_frame`].
///
/// Linux semantics: takes no arguments, never returns to its caller in
/// the C sense — it rewrites the saved register state so the
/// syscall-return path resumes at the pre-signal `RIP/RSP/RFLAGS` with
/// the pre-signal GPRs and the pre-handler signal mask.
///
/// At `rt_sigreturn` entry the user stack looks like this (the handler
/// has already `ret`'d through `pretcode` into `sa_restorer`, which then
/// did `mov $15,%rax; syscall`), so `%rsp` points exactly at the
/// embedded `ucontext`:
///
/// ```text
///   user_rsp ─▶ ucontext   (304 bytes; uc_mcontext at +40)
///              siginfo     (128 bytes)
/// ```
///
/// We read the `ucontext`, restore every GPR from `uc_mcontext`, restore
/// `RIP`/`RSP`, sanitise `RFLAGS` (see [`SIGRETURN_RFLAGS_USER_MASK`]),
/// restore the blocked signal mask from `uc_sigmask`, and return
/// `uc_mcontext.rax` as the syscall result (which the SYSRET path loads
/// into the resumed `RAX`).
///
/// If the `ucontext` is not a readable, suitably-aligned user mapping we
/// return `-EFAULT` and leave the frame untouched: a malformed
/// `rt_sigreturn` would otherwise let userspace point `RIP` anywhere.
fn linux_rt_sigreturn(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    use crate::proc::linux_sigframe::LinuxUcontext;

    let uc_addr = frame.user_rsp;
    let uc_size = core::mem::size_of::<LinuxUcontext>();
    // The ucontext is 8-byte aligned by construction (frame_addr ≡ 8
    // mod 16, +8 for pretcode ⇒ uc_addr ≡ 0 mod 16).  Reject a bogus
    // unaligned pointer before the unsafe read.
    if uc_addr == 0 || (uc_addr & 0x7) != 0 {
        return -i64::from(errno::EFAULT);
    }
    if crate::mm::user::validate_user_read(uc_addr, uc_size).is_err() {
        return -i64::from(errno::EFAULT);
    }

    // SAFETY: validated above as a readable user mapping spanning the
    // whole ucontext, and 8-byte aligned (LinuxUcontext's alignment).
    // CR3 still points at this process's address space (we are returning
    // to it).  read_unaligned is used defensively even though alignment
    // is guaranteed.
    let uc = unsafe { core::ptr::read_unaligned(uc_addr as *const LinuxUcontext) };
    let mc = &uc.uc_mcontext;

    // Restore the interrupted GPRs from uc_mcontext.
    frame.arg0 = mc.rdi;
    frame.arg1 = mc.rsi;
    frame.arg2 = mc.rdx;
    frame.arg3 = mc.r10;
    frame.arg4 = mc.r8;
    frame.arg5 = mc.r9;
    frame.rbx = mc.rbx;
    frame.rbp = mc.rbp;
    frame.r12 = mc.r12;
    frame.r13 = mc.r13;
    frame.r14 = mc.r14;
    frame.r15 = mc.r15;
    frame.user_rip = mc.rip;
    frame.user_rsp = mc.rsp;
    frame.user_rflags =
        (mc.eflags & SIGRETURN_RFLAGS_USER_MASK) | SIGRETURN_RFLAGS_FORCED;

    // Restore the pre-handler blocked mask.  set_blocked strips
    // SIGKILL/SIGSTOP, so a crafted uc_sigmask cannot wedge those.
    if let Some(pid) = caller_pid() {
        let _ = crate::proc::signal::set_blocked(pid, uc.uc_sigmask);
    }

    // The resumed RAX is whatever the interrupted context held (the
    // value the pre-signal syscall was about to return, captured in
    // uc_mcontext.rax at delivery time).
    #[allow(clippy::cast_possible_wrap)]
    {
        mc.rax as i64
    }
}

/// Per-signal disposition for a Linux-ABI process, resolved from the
/// per-process [`LinuxSigaction`] table.
pub enum LinuxDisposition {
    /// A user handler is installed; build an `rt_sigframe` and enter it.
    Handler(LinuxSigaction),
    /// Explicit `SIG_IGN`: drop the signal silently.
    Ignore,
    /// `SIG_DFL`: apply the kernel default action (terminate/stop/ignore).
    Default,
}

/// Resolve how a Linux-ABI process should react to signal `sig`.
///
/// Consults the per-signal `struct sigaction` table (not the legacy
/// single-trampoline pointer), so each signal gets its own disposition —
/// exactly as Linux does.
#[must_use]
pub fn linux_disposition(pid: pcb::ProcessId, sig: u32) -> LinuxDisposition {
    let act = linux_sigaction_get(pid, sig);
    match act.sa_handler {
        SIG_DFL => LinuxDisposition::Default,
        SIG_IGN => LinuxDisposition::Ignore,
        _ => LinuxDisposition::Handler(act),
    }
}

/// Neutral register snapshot used to populate a Linux `uc_mcontext` when
/// building an `rt_sigframe`.  Decouples the frame builder from the specific
/// trap context the registers were captured in — a syscall-entry
/// [`SyscallFrame`](crate::syscall::entry::SyscallFrame) (asynchronous signal
/// delivered at syscall return) or a hardware-exception ISR frame
/// (synchronous fault) — so both paths share one emitter.
#[derive(Debug, Clone, Copy)]
pub struct LinuxTrapRegs {
    pub rax: u64,
    pub rbx: u64,
    pub rcx: u64,
    pub rdx: u64,
    pub rsi: u64,
    pub rdi: u64,
    pub rbp: u64,
    pub r8: u64,
    pub r9: u64,
    pub r10: u64,
    pub r11: u64,
    pub r12: u64,
    pub r13: u64,
    pub r14: u64,
    pub r15: u64,
    pub rip: u64,
    pub rsp: u64,
    pub rflags: u64,
}

/// Register values a caller must install into its trap/syscall frame to enter
/// a signal handler, returned by [`emit_linux_rt_frame`].
#[derive(Debug, Clone, Copy)]
pub struct RtFrameEntry {
    /// Handler entry point → `rip`.
    pub rip: u64,
    /// Frame base (`pretcode` = `sa_restorer`) → `rsp`.
    pub rsp: u64,
    /// `rdi` = signal number.
    pub rdi: u64,
    /// `rsi` = &siginfo.
    pub rsi: u64,
    /// `rdx` = &ucontext.
    pub rdx: u64,
    /// `rflags` to enter the handler with (IF set, DF/TF clear).
    pub rflags: u64,
}

/// Lay out and write a byte-exact Linux `struct rt_sigframe` onto the user
/// stack from a neutral register snapshot, returning the register values the
/// caller must install to enter the handler.
///
/// This is the shared core behind both [`build_linux_rt_frame`] (asynchronous
/// signals delivered at syscall return) and the synchronous fault-delivery
/// path in the exception ISRs (`crate::idt`).  It performs **no re-arming**
/// on failure: a `None` return means the frame could not be written (user
/// stack would underflow or is not writable), and the caller decides the
/// fallback — re-arm + retry for an asynchronous signal, or force-default
/// (terminate) for a synchronous fault, which cannot be retried because
/// resuming would just re-execute the faulting instruction.
#[must_use]
pub fn emit_linux_rt_frame(
    pid: pcb::ProcessId,
    sig: u32,
    act: &LinuxSigaction,
    regs: &LinuxTrapRegs,
    siginfo: crate::proc::linux_sigframe::LinuxSiginfo,
) -> Option<RtFrameEntry> {
    use crate::proc::linux_sigframe::{
        self, FrameLayout, LinuxSigcontext, LinuxStackT, LinuxUcontext,
        RT_SIGFRAME_SIZE,
    };
    use crate::proc::signal;

    // Where does the frame land on the user stack?  Underflow ⇒ fail.
    let layout: FrameLayout = linux_sigframe::compute_layout(regs.rsp)?;

    // Validate the whole frame region [frame_addr, frame_addr + size) is
    // writable user memory before touching it.
    if crate::mm::user::validate_user_write(layout.frame_addr, RT_SIGFRAME_SIZE)
        .is_err()
    {
        return None;
    }

    // ---- compute the new blocked mask (effective during the handler) ----
    // `current_blocked` is the mask in effect right now: normally the
    // process's blocked mask, but during a `sigsuspend` it is the temporary
    // suspend mask. The handler runs with `current_blocked | sa_mask | sig`
    // (Linux `signal_delivered`).
    //
    // `restore_blocked` is the mask `rt_sigreturn` restores via `uc_sigmask`.
    // Normally that equals `current_blocked`, but if a `sigsuspend` saved a
    // mask (Linux `TIF_RESTORE_SIGMASK`), the *original* pre-suspend mask is
    // the one to restore — and consuming it here clears the restore flag,
    // matching Linux clearing the flag in `signal_delivered`.
    let current_blocked = signal::blocked(pid);
    let restore_blocked =
        signal::take_saved_sigmask(pid).unwrap_or(current_blocked);
    let sig_bit = 1u64 << (u64::from(sig).saturating_sub(1) & 63);
    let mut new_blocked = current_blocked | act.sa_mask;
    // Unless SA_NODEFER, the delivered signal is blocked during its own
    // handler so it can't recursively re-enter.
    if (act.sa_flags & sa_flags::SA_NODEFER) == 0 {
        new_blocked |= sig_bit;
    }

    // ---- build the saved machine context (uc_mcontext) ----
    // fpstate stays 0 (NULL) via Default: no FP context is saved, so
    // rt_sigreturn skips the FP restore.
    let sc = LinuxSigcontext {
        rdi: regs.rdi,
        rsi: regs.rsi,
        rdx: regs.rdx,
        r10: regs.r10,
        r8: regs.r8,
        r9: regs.r9,
        rbx: regs.rbx,
        rbp: regs.rbp,
        r12: regs.r12,
        r13: regs.r13,
        r14: regs.r14,
        r15: regs.r15,
        rip: regs.rip,
        rsp: regs.rsp,
        rax: regs.rax,
        rcx: regs.rcx,
        r11: regs.r11,
        eflags: regs.rflags,
        cs: crate::gdt::USER_CS,
        ss: crate::gdt::USER_DS,
        // oldmask is the deprecated low-32 signal mask; glibc reads
        // uc_sigmask instead, but fill it for completeness.
        oldmask: restore_blocked,
        ..LinuxSigcontext::default()
    };

    let uc = LinuxUcontext {
        uc_flags: 0,
        uc_link: 0,
        uc_stack: LinuxStackT {
            ss_sp: 0,
            // SS_DISABLE (2): no alternate signal stack installed.
            ss_flags: 2,
            _pad: 0,
            ss_size: 0,
        },
        uc_mcontext: sc,
        // Restored by rt_sigreturn: the mask in effect before the handler
        // ran — or, after a sigsuspend, the original pre-suspend mask.
        uc_sigmask: restore_blocked,
    };

    // ---- write the frame to user memory ----
    // SAFETY: the region [frame_addr, frame_addr + RT_SIGFRAME_SIZE) was
    // validated as writable user memory above; uc_addr/info_addr lie
    // within it (see compute_layout), and CR3 points at this process's
    // address space.  write_unaligned avoids any alignment assumption.
    unsafe {
        core::ptr::write_unaligned(layout.frame_addr as *mut u64, act.sa_restorer);
        core::ptr::write_unaligned(layout.uc_addr as *mut LinuxUcontext, uc);
        core::ptr::write_unaligned(
            layout.info_addr as *mut linux_sigframe::LinuxSiginfo,
            siginfo,
        );
    }

    // ---- apply the new blocked mask ----
    let _ = signal::set_blocked(pid, new_blocked);

    // ---- SA_RESETHAND: one-shot handler resets to SIG_DFL ----
    if (act.sa_flags & sa_flags::SA_RESETHAND) != 0 {
        linux_sigaction_set(pid, sig, LinuxSigaction::default());
    }

    Some(RtFrameEntry {
        rip: act.sa_handler,
        rsp: layout.frame_addr,
        rdi: u64::from(sig),
        rsi: layout.info_addr,
        rdx: layout.uc_addr,
        // Enter the handler with a clean RFLAGS: IF set, DF/TF cleared (a
        // handler must run with DF=0 per the SysV ABI).
        rflags: SIGRETURN_RFLAGS_FORCED,
    })
}

/// Build a byte-exact Linux `struct rt_sigframe` on the user stack and
/// rewrite the syscall frame so the SYSRET path enters the handler.
///
/// This is the Linux-ABI counterpart of the native trampoline path in
/// [`crate::syscall::handlers::deliver_pending_signal`].  An unmodified
/// glibc (or WINE) handler installed via `rt_sigaction` expects:
///
///   * `%rdi = signo`, `%rsi = &siginfo`, `%rdx = &ucontext`;
///   * `%rsp` pointing at `pretcode` (= `sa_restorer`), which the handler
///     `ret`s into to reach `rt_sigreturn`;
///   * a fully-populated `siginfo` and `ucontext` at the advertised
///     addresses.
///
/// `ret_val` is the value the interrupted syscall was about to return; it
/// is stashed in `uc_mcontext.rax` and restored by [`linux_rt_sigreturn`].
///
/// Returns `true` on successful delivery (frame rewritten, one signal
/// consumed).  Returns `false` if the user stack cannot hold the frame —
/// in that case the signal is re-armed (left pending) for the next
/// return-to-user, and the caller should fall back to the normal return
/// value.
#[must_use]
pub fn build_linux_rt_frame(
    frame: &mut crate::syscall::entry::SyscallFrame,
    ret_val: i64,
    pid: pcb::ProcessId,
    sig: u32,
    act: &LinuxSigaction,
    info: crate::proc::signal::SigInfo,
) -> bool {
    use crate::proc::signal;

    // SA_RESTART: a handler is about to run, so resolve any restart sentinel
    // the interrupted syscall returned.  Either we rewind so the syscall
    // re-executes after the handler returns (RAX = original nr, RIP = the
    // `syscall` instruction), or we convert the sentinel to the user-visible
    // -EINTR.  A non-sentinel return value is passed through unchanged.  See
    // [`restart::restart_action`].
    let (saved_rax, saved_rip) = match restart::sentinel_magnitude(ret_val) {
        Some(sentinel) => {
            let sa_restart = (act.sa_flags & sa_flags::SA_RESTART) != 0;
            match restart::restart_action(sentinel, true, sa_restart) {
                restart::RestartAction::Restart => (
                    frame.syscall_nr,
                    frame.user_rip.wrapping_sub(restart::SYSCALL_INSN_LEN),
                ),
                // With a handler running, RestartBlock collapses to EINTR
                // (restart_action returns Eintr for it when has_handler=true);
                // both arms therefore yield the user-visible -EINTR at the
                // unchanged RIP.  A handler-delivered EINTR also means no
                // restart_syscall will be issued, so invalidate any saved
                // restart block (e.g. an interrupted nanosleep's) — matching
                // Linux resetting restart_block.fn to do_no_restart_syscall —
                // so a later stray restart_syscall can't replay a stale sleep.
                restart::RestartAction::RestartBlock | restart::RestartAction::Eintr => {
                    restart_block::clear(crate::sched::current_task_id());
                    ((-i64::from(errno::EINTR)) as u64, frame.user_rip)
                }
            }
        }
        #[allow(clippy::cast_sign_loss)]
        None => (ret_val as u64, frame.user_rip),
    };

    // Snapshot the interrupted syscall context.  rcx/r11 are clobbered by the
    // `syscall` instruction; their architectural values are the return RIP and
    // saved RFLAGS, so reproduce that.  RAX resumes with the syscall's pending
    // return value (or, on restart, the original syscall number).
    let regs = LinuxTrapRegs {
        rax: saved_rax,
        rbx: frame.rbx,
        rcx: saved_rip,
        rdx: frame.arg2,
        rsi: frame.arg1,
        rdi: frame.arg0,
        rbp: frame.rbp,
        r8: frame.arg4,
        r9: frame.arg5,
        r10: frame.arg3,
        r11: frame.user_rflags,
        r12: frame.r12,
        r13: frame.r13,
        r14: frame.r14,
        r15: frame.r15,
        rip: saved_rip,
        rsp: frame.user_rsp,
        rflags: frame.user_rflags,
    };

    // Async (process-directed) signal: fill siginfo from the recorded source
    // metadata (si_code + sender pid/uid captured at post time). A queued
    // signal (`sigqueue`/`rt_sigqueueinfo`, SI_QUEUE) additionally carries the
    // user-supplied `si_value` payload at union+8; every other class leaves it
    // zero, so we use the `_rt`-layout builder only for SI_QUEUE.
    #[allow(clippy::cast_possible_wrap)]
    let signo_i = sig as i32;
    #[allow(clippy::cast_possible_wrap)]
    let sender_pid_i = info.sender_pid as i32;
    let siginfo = if info.code == crate::proc::signal::si_code::SI_QUEUE {
        crate::proc::linux_sigframe::LinuxSiginfo::queue(
            signo_i,
            info.code,
            sender_pid_i,
            info.sender_uid,
            info.value,
        )
    } else {
        crate::proc::linux_sigframe::LinuxSiginfo::kill(
            signo_i,
            info.code,
            sender_pid_i,
            info.sender_uid,
        )
    };

    match emit_linux_rt_frame(pid, sig, act, &regs, siginfo) {
        Some(entry) => {
            frame.user_rip = entry.rip;
            frame.user_rsp = entry.rsp;
            frame.arg0 = entry.rdi; // rdi = signo
            frame.arg1 = entry.rsi; // rsi = &siginfo
            frame.arg2 = entry.rdx; // rdx = &ucontext
            frame.arg3 = 0; // r10
            frame.arg4 = 0; // r8
            frame.arg5 = 0; // r9
            frame.user_rflags = entry.rflags;
            true
        }
        None => {
            // User stack unusable — re-arm (preserving the faithful `info`)
            // so a later return-to-user retries delivery, exactly like the
            // native path (a future sigaltstack would give a fallback stack).
            let _ = signal::set_pending_info(pid, sig, info);
            false
        }
    }
}

/// Linux `fork()` / `vfork()` translation.
///
/// vfork is implemented identically to fork: the Linux `vfork()`
/// optimisation (parent blocks until child execs/exits, child shares
/// parent's pages) is a performance hint, not a correctness
/// requirement — every conformant caller of vfork must work correctly
/// against a plain fork.  We pay the CoW page table walk vfork was
/// trying to avoid, but the program behaves the same.
fn linux_fork(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    linux_fork_common(frame, crate::proc::fork::ForkCloneTid::default())
}

/// Shared fork body for `linux_fork` (plain `FORK`/`VFORK`) and the
/// `clone()` fork-equivalent path.  `clone_tid` carries the TID-
/// notification bits glibc's `fork()` passes
/// (`CLONE_CHILD_SETTID | CLONE_CHILD_CLEARTID`, optionally
/// `CLONE_PARENT_SETTID`); plain fork/vfork pass an all-zero value.
fn linux_fork_common(
    frame: &mut crate::syscall::entry::SyscallFrame,
    clone_tid: crate::proc::fork::ForkCloneTid,
) -> i64 {
    use crate::proc::{fork, thread};

    let task_id = crate::sched::current_task_id();
    let parent_pid = match thread::owner_process(task_id) {
        Some(pid) if pid != 0 => pid,
        _ => return -i64::from(errno::ESRCH),
    };

    match fork::fork_process_clone(parent_pid, frame, clone_tid) {
        Ok(child_pid) => {
            #[allow(clippy::cast_possible_wrap)]
            {
                child_pid as i64
            }
        }
        Err(e) => -i64::from(linux_errno_for(e)),
    }
}

/// Linux `clone()` translation.
///
/// Linux `clone(flags, child_stack, ptid, ctid, tls)` is the swiss-
/// army knife behind both `fork()` and `pthread_create()`.  We split
/// it three ways:
///
///   1. **Thread creation** (`CLONE_VM | CLONE_THREAD` set, non-zero
///      `child_stack`) — routes to
///      [`crate::proc::thread_clone::clone_thread`] which spawns a
///      new ring-3 thread sharing the parent's address space, fd
///      table, signal handlers, and credentials.  Honours
///      `CLONE_SETTLS` (FS base), `CLONE_PARENT_SETTID` /
///      `CLONE_CHILD_SETTID` (TID notification), and
///      `CLONE_CHILD_CLEARTID` (futex-wake on exit, for
///      `pthread_join`).
///   2. **Fork-equivalent** (`CLONE_VM` clear, `child_stack == 0`) —
///      glibc's `fork()` wrapper issues `clone(SIGCHLD, 0, ...)`.
///      Routes to [`linux_fork`].
///   3. **Unsupported combinations** (vfork, namespace clones,
///      ptrace, partial-share flag sets that don't match (1) or
///      (2)) — return `-ENOSYS`.
fn linux_clone(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    let flags = frame.arg0;
    let child_stack = frame.arg1;
    let parent_tid_ptr = frame.arg2;
    // Linux x86_64 ABI: clone(flags, stack, ptid, ctid, tls) maps to
    // (rdi, rsi, rdx, r10, r8) which in our SyscallFrame are
    // (arg0, arg1, arg2, arg3, arg4).
    let child_tid_ptr = frame.arg3;
    let new_tls = frame.arg4;
    linux_clone_inner(flags, child_stack, parent_tid_ptr, child_tid_ptr, new_tls, frame)
}

/// Shared inner of `linux_clone` and `linux_clone3` — does the actual
/// flag/stack dispatch into either the thread-creation path or
/// fork-equivalent path.  All five Linux-ABI clone() args are passed
/// explicitly so clone3 can translate from its `struct clone_args`
/// layout (separate stack base + size, separate pidfd / set_tid /
/// cgroup fields) without having to scribble on `frame`.
///
/// The frame is still needed so the new task can inherit the parent's
/// register state — both `thread_clone::clone_thread` and
/// `fork::fork_process` read it for the child's saved-context image.
fn linux_clone_inner(
    flags: u64,
    child_stack: u64,
    parent_tid_ptr: u64,
    child_tid_ptr: u64,
    new_tls: u64,
    frame: &mut crate::syscall::entry::SyscallFrame,
) -> i64 {
    use crate::proc::{thread, thread_clone};

    // (1) Thread-creation path: requires CLONE_VM | CLONE_THREAD AND
    //     a non-zero child_stack.  glibc's pthread_create wrapper
    //     also passes CLONE_FS | CLONE_FILES | CLONE_SIGHAND |
    //     CLONE_SYSVSEM (all of which we share by virtue of sharing
    //     the PCB), plus CLONE_SETTLS and the TID notification bits.
    const THREAD_REQUIRED: u64 =
        clone_flags::CLONE_VM | clone_flags::CLONE_THREAD;
    if (flags & THREAD_REQUIRED) == THREAD_REQUIRED && child_stack != 0 {
        // CLONE_VFORK on a thread-creation clone is nonsensical — the
        // new "child" shares the address space, so blocking the
        // parent until the child execs/exits is meaningless.  Reject
        // unambiguously.  CLONE_PARENT / CLONE_NEWNS / CLONE_PTRACE
        // need infrastructure (PID reparenting, mount namespaces,
        // ptrace lineage) we don't have yet.
        const UNSUPPORTED_BITS: u64 = clone_flags::CLONE_VFORK
            | clone_flags::CLONE_PARENT
            | clone_flags::CLONE_NEWNS
            | clone_flags::CLONE_PTRACE;
        if (flags & UNSUPPORTED_BITS) != 0 {
            return -i64::from(errno::ENOSYS);
        }

        // CLONE_SETTLS with a non-canonical or kernel-half TLS base
        // would feed the child trampoline's WRMSR(IA32_FS_BASE, …) a
        // value that either crashes the kernel synchronously (#GP on
        // non-canonical, per Intel SDM Vol 3A §4.4) or installs a
        // kernel pointer into the child's FS.  Reject up-front with
        // -EPERM to mirror what `arch_prctl(ARCH_SET_FS, …)` does for
        // the equivalent direct path (see [`USER_FS_BASE_MAX`]).  Gate
        // on CLONE_SETTLS so we don't penalise plain clone() callers
        // who happen to have garbage in arg4, and on new_tls != 0
        // because the trampoline treats 0 as "leave the inherited MSR
        // alone" — no WRMSR will fire and there is nothing to
        // validate.
        if (flags & clone_flags::CLONE_SETTLS) != 0
            && new_tls != 0
            && new_tls >= USER_FS_BASE_MAX
        {
            return -i64::from(errno::EPERM);
        }

        let task_id = crate::sched::current_task_id();
        let parent_pid = match thread::owner_process(task_id) {
            Some(pid) if pid != 0 => pid,
            _ => return -i64::from(errno::ESRCH),
        };

        let args = thread_clone::CloneThreadArgs {
            flags,
            child_stack,
            parent_tid_ptr,
            child_tid_ptr,
            new_tls,
        };
        return match thread_clone::clone_thread(parent_pid, frame, &args) {
            Ok(new_tid) => i64::try_from(new_tid).unwrap_or(i64::MAX),
            Err(e) => -i64::from(linux_errno_for(e)),
        };
    }

    // (1.5) vfork-style spawn (glibc `posix_spawn(3)` / `vfork()`):
    // clone with CLONE_VM | CLONE_VFORK but NOT CLONE_THREAD, and a
    // caller-provided child stack.  This is how glibc launches a child
    // for posix_spawn — the child runs a tiny trampoline
    // (`__spawni_child`) on `child_stack`, which on Linux executes in a
    // *shared* address space, then immediately execve's or _exit's
    // while CLONE_VFORK suspends the parent.  We can't share the
    // address space (our processes are isolated), so we degenerate to a
    // copy-on-write fork — identical to how plain CLONE_VFORK is
    // handled in (3) below — but the child must resume on `child_stack`
    // per the clone(2) contract for a non-NULL stack.  Full rationale,
    // including the execve-failure errno degradation, lives on
    // `fork::fork_process_vfork`.
    const VFORK_SPAWN: u64 = clone_flags::CLONE_VM | clone_flags::CLONE_VFORK;
    if (flags & VFORK_SPAWN) == VFORK_SPAWN && child_stack != 0 {
        // Resource-sharing / namespace / ptrace bits we cannot honour
        // even on this path: a CoW fork gives the child independent
        // copies, so a caller that genuinely wanted shared fd tables or
        // signal handlers would observe wrong behaviour.  glibc's
        // posix_spawn sets none of these (only CLONE_VM | CLONE_VFORK
        // plus the exit-signal byte and TID-notification bits), so this
        // is a guard against unsupported callers, not posix_spawn.
        const VFORK_REJECTED_BITS: u64 = clone_flags::CLONE_FS
            | clone_flags::CLONE_FILES
            | clone_flags::CLONE_SIGHAND
            | clone_flags::CLONE_THREAD
            | clone_flags::CLONE_SYSVSEM
            | clone_flags::CLONE_SETTLS
            | clone_flags::CLONE_PARENT
            | clone_flags::CLONE_NEWNS
            | clone_flags::CLONE_PTRACE;
        if flags & VFORK_REJECTED_BITS != 0 {
            return -i64::from(errno::ENOSYS);
        }

        let task_id = crate::sched::current_task_id();
        let parent_pid = match thread::owner_process(task_id) {
            Some(pid) if pid != 0 => pid,
            _ => return -i64::from(errno::ESRCH),
        };

        let clone_tid = crate::proc::fork::ForkCloneTid {
            flags,
            parent_tid_ptr,
            child_tid_ptr,
        };
        return match crate::proc::fork::fork_process_vfork(
            parent_pid,
            frame,
            clone_tid,
            child_stack,
        ) {
            Ok(child_pid) => {
                // CLONE_CLEAR_SIGHAND: reset the child's kernel-side signal
                // state (trampoline + blocked mask) to defaults.  The child
                // normally execs immediately (which does this anyway via
                // on_exec), but honouring it here keeps the contract for any
                // child that delays or skips exec.
                if flags & clone_flags::CLONE_CLEAR_SIGHAND != 0 {
                    crate::proc::signal::on_exec(child_pid);
                }
                #[allow(clippy::cast_possible_wrap)]
                {
                    child_pid as i64
                }
            }
            Err(e) => -i64::from(linux_errno_for(e)),
        };
    }

    // (2) Anything-but-fork: a non-zero child_stack outside the
    // thread path is invalid.  Same for any "share with parent" bit
    // without the full CLONE_VM | CLONE_THREAD pairing — we can't
    // honour partial sharing (e.g. CLONE_FILES alone) because our
    // PCB model is per-process, not per-resource-table.
    if child_stack != 0 {
        return -i64::from(errno::ENOSYS);
    }

    // Resource-sharing bits we cannot honour outside the full
    // thread-creation path: our PCB is per-process, not
    // per-resource-table, so partial sharing (e.g. CLONE_FILES alone)
    // is impossible.  CLONE_SETTLS is likewise rejected here — a fork
    // inherits the parent's FS base via the duplicated address space, so
    // a *different* TLS base for the child would need trampoline plumbing
    // we don't have and no real fork() caller requests.
    //
    // The TID-notification bits (CLONE_PARENT_SETTID, CLONE_CHILD_SETTID,
    // CLONE_CHILD_CLEARTID) are intentionally NOT rejected: glibc's
    // fork() issues clone(CLONE_CHILD_SETTID | CLONE_CHILD_CLEARTID |
    // SIGCHLD, …) and we honour them in fork_process_clone /
    // fork_child_trampoline.
    const FORK_REJECTED_SHARE_BITS: u64 = clone_flags::CLONE_VM
        | clone_flags::CLONE_FS
        | clone_flags::CLONE_FILES
        | clone_flags::CLONE_SIGHAND
        | clone_flags::CLONE_THREAD
        | clone_flags::CLONE_SYSVSEM
        | clone_flags::CLONE_SETTLS;
    if flags & FORK_REJECTED_SHARE_BITS != 0 {
        return -i64::from(errno::ENOSYS);
    }

    // CLONE_PARENT / CLONE_NEWNS / CLONE_PTRACE need infrastructure
    // we don't have (PID reparenting, mount namespaces, ptrace
    // lineage) — reject up-front.
    const UNSUPPORTED_BITS: u64 = clone_flags::CLONE_PARENT
        | clone_flags::CLONE_NEWNS
        | clone_flags::CLONE_PTRACE;
    if flags & UNSUPPORTED_BITS != 0 {
        return -i64::from(errno::ENOSYS);
    }

    // CLONE_VFORK is *accepted* and degenerates to a plain fork.
    // Linux's vfork() guarantees:
    //   (a) the parent blocks until the child execve's or _exit's,
    //   (b) the child shares the parent's address space until then.
    // (a) is a *performance hint*, not a correctness requirement —
    // every conformant caller of vfork must already work against a
    // plain fork (POSIX explicitly permits implementations to make
    // vfork == fork).  (b) we don't honour, but CoW gives the child
    // a logically identical address space.  We pay a CoW page-table
    // walk vfork was trying to avoid, but the program behaves the
    // same.  Identical semantics to the dedicated VFORK syscall
    // (see `linux_fork` doc-comment).  Limitation tracked in
    // `todo.txt`.
    //
    // Everything that remains is just the CSIGNAL byte, optionally
    // CLONE_VFORK, plus the TID-notification bits — fork-equivalent.
    // glibc fork() passes SIGCHLD | CLONE_CHILD_SETTID |
    // CLONE_CHILD_CLEARTID with ctid pointing at the child's TCB tid
    // slot; thread those through so the child's TID is written and the
    // exit-time clear/futex-wake is registered.  We don't deliver the
    // SIGCHLD signal yet (no Unix-style signals to userspace), but the
    // kernel already records parent/child relationships in the PCB.
    let clone_tid = crate::proc::fork::ForkCloneTid {
        flags,
        parent_tid_ptr,
        child_tid_ptr,
    };
    linux_fork_common(frame, clone_tid)
}

/// Maximum length of a single NUL-terminated string read from
/// userspace during `execve` argument marshalling.  Matches Linux's
/// `MAX_ARG_STRLEN` ceiling at 128 KiB but our typical use cases are
/// far smaller — most argv entries are tens of bytes.
const EXECVE_MAX_STR_LEN: usize = 128 * 1024;

/// Maximum number of entries in `argv` or `envp` during `execve`.
/// Linux uses `MAX_ARG_STRINGS = 0x7FFFFFFF`, but a realistic cap
/// limits how badly a malicious caller can hold us in the pointer
/// walk before we bail out.
const EXECVE_MAX_ARGS: usize = 2048;

/// Aggregate cap on total argv+envp bytes — matches the cap that
/// `sys_process_exec_with_frame` uses for the native path.
const EXECVE_MAX_TOTAL_BYTES: usize = 256 * 1024;

/// Read a NUL-terminated byte string from `ptr` in userspace, up to
/// `max_len` bytes (not counting the NUL).  Returns the bytes
/// (without the terminator) on success, or an `errno` value on
/// failure.
fn read_user_cstr(ptr: u64, max_len: usize) -> Result<alloc::vec::Vec<u8>, i32> {
    if ptr == 0 {
        return Err(errno::EFAULT);
    }
    let mut buf: alloc::vec::Vec<u8> = alloc::vec::Vec::new();
    let mut i: usize = 0;
    while i <= max_len {
        let mut b: u8 = 0;
        // SAFETY: copy_from_user validates the one-byte user range
        // before touching it and uses STAC/CLAC for SMAP.
        let r = unsafe {
            crate::mm::user::copy_from_user(
                ptr.wrapping_add(i as u64),
                &raw mut b,
                1,
            )
        };
        if let Err(e) = r {
            return Err(linux_errno_for(e));
        }
        if b == 0 {
            return Ok(buf);
        }
        if i == max_len {
            // Found a non-NUL byte at position max_len, meaning the
            // string is longer than allowed.
            return Err(errno::ENAMETOOLONG);
        }
        buf.push(b);
        i += 1;
    }
    Err(errno::ENAMETOOLONG)
}

/// Read a NULL-terminated array of `u64` user pointers (argv/envp)
/// starting at `ptr`, with at most `max_entries` non-NULL entries.
/// A `ptr` of 0 is treated as an empty array (matching what glibc
/// passes when the program had no arguments).
fn read_user_ptr_array(
    ptr: u64,
    max_entries: usize,
) -> Result<alloc::vec::Vec<u64>, i32> {
    if ptr == 0 {
        return Ok(alloc::vec::Vec::new());
    }
    let mut out: alloc::vec::Vec<u64> = alloc::vec::Vec::new();
    for i in 0..=max_entries {
        let mut p: u64 = 0;
        // SAFETY: copy_from_user validates the 8-byte user range
        // before touching it.
        let r = unsafe {
            crate::mm::user::copy_from_user(
                ptr.wrapping_add((i * 8) as u64),
                (&raw mut p).cast::<u8>(),
                8,
            )
        };
        if let Err(e) = r {
            return Err(linux_errno_for(e));
        }
        if p == 0 {
            return Ok(out);
        }
        if i == max_entries {
            return Err(errno::E2BIG);
        }
        out.push(p);
    }
    Err(errno::E2BIG)
}

/// Linux `execve(filename, argv[], envp[])` translation.
///
/// Resolves `filename` through the VFS, loads the file into a kernel
/// buffer, walks the userspace `argv` and `envp` pointer arrays
/// reading each NUL-terminated string into kernel buffers, then
/// hands off to `proc::spawn::exec_process`.  All argument
/// marshalling completes BEFORE the old address space is torn down,
/// so a malformed-argv `execve` leaves the caller's image intact.
///
/// On success the saved syscall frame is rewritten so SYSRET returns
/// to the new entry point with a clean register state, matching the
/// native `sys_process_exec_with_frame` behaviour.  On failure the
/// caller observes a Linux `-errno` and continues running.
fn linux_execve(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    let filename_ptr = frame.arg0;
    let argv_user = frame.arg1;
    let envp_user = frame.arg2;

    // Read filename.
    // PATH_MAX on Linux is 4096; our VFS uses str so we additionally
    // require valid UTF-8 (Linux accepts arbitrary bytes — the path
    // is "all bytes except / and NUL").  Treat invalid UTF-8 as
    // ENOENT (the file by that name doesn't exist on a UTF-8 VFS).
    const PATH_MAX: usize = 4096;
    let filename_bytes = match read_user_cstr(filename_ptr, PATH_MAX) {
        Ok(b) => b,
        Err(e) => return -i64::from(e),
    };
    if filename_bytes.is_empty() {
        return -i64::from(errno::ENOENT);
    }
    let filename = match core::str::from_utf8(&filename_bytes) {
        Ok(s) => s,
        Err(_) => return -i64::from(errno::ENOENT),
    };
    linux_exec_common(frame, filename, &filename_bytes, argv_user, envp_user)
}

/// Shared core of `execve` / `execveat`.
///
/// With the executable already resolved to `filename` (a VFS-openable
/// path) and `filename_bytes` (the original path bytes, used for the
/// `/proc/<pid>/exe` link), read argv / envp from the userspace pointer
/// arrays, load the image, and rewrite `frame` to land at the new entry
/// point on success.  On any error the old address space is left intact
/// and the negative errno is returned.
fn linux_exec_common(
    frame: &mut crate::syscall::entry::SyscallFrame,
    filename: &str,
    filename_bytes: &[u8],
    argv_user: u64,
    envp_user: u64,
) -> i64 {
    use crate::proc::{signal, spawn::exec_process, thread};

    // ---- 1. Resolve caller's PID. ----
    let task_id = crate::sched::current_task_id();
    let pid = match thread::owner_process(task_id) {
        Some(pid) if pid != 0 => pid,
        _ => return -i64::from(errno::ESRCH),
    };

    // ---- 3. Read argv and envp pointer arrays. ----
    let argv_ptrs = match read_user_ptr_array(argv_user, EXECVE_MAX_ARGS) {
        Ok(v) => v,
        Err(e) => return -i64::from(e),
    };
    let envp_ptrs = match read_user_ptr_array(envp_user, EXECVE_MAX_ARGS) {
        Ok(v) => v,
        Err(e) => return -i64::from(e),
    };

    // ---- 4. Read each argv / envp string into a kernel buffer. ----
    let mut total_bytes: usize = 0;
    let mut argv_bufs: alloc::vec::Vec<alloc::vec::Vec<u8>> =
        alloc::vec::Vec::with_capacity(argv_ptrs.len());
    for p in argv_ptrs {
        let s = match read_user_cstr(p, EXECVE_MAX_STR_LEN) {
            Ok(s) => s,
            Err(e) => return -i64::from(e),
        };
        total_bytes = total_bytes.saturating_add(s.len()).saturating_add(1);
        if total_bytes > EXECVE_MAX_TOTAL_BYTES {
            return -i64::from(errno::E2BIG);
        }
        argv_bufs.push(s);
    }
    let mut envp_bufs: alloc::vec::Vec<alloc::vec::Vec<u8>> =
        alloc::vec::Vec::with_capacity(envp_ptrs.len());
    for p in envp_ptrs {
        let s = match read_user_cstr(p, EXECVE_MAX_STR_LEN) {
            Ok(s) => s,
            Err(e) => return -i64::from(e),
        };
        total_bytes = total_bytes.saturating_add(s.len()).saturating_add(1);
        if total_bytes > EXECVE_MAX_TOTAL_BYTES {
            return -i64::from(errno::E2BIG);
        }
        envp_bufs.push(s);
    }

    // ---- 5. Read file from VFS BEFORE tearing down old AS. ----
    let elf_data = match crate::fs::vfs::Vfs::read_file(filename) {
        Ok(d) => d,
        Err(e) => return -i64::from(linux_errno_for(e)),
    };

    // ---- 6. Build &[&[u8]] views for exec_process. ----
    let argv_slices: alloc::vec::Vec<&[u8]> =
        argv_bufs.iter().map(alloc::vec::Vec::as_slice).collect();
    let envp_slices: alloc::vec::Vec<&[u8]> =
        envp_bufs.iter().map(alloc::vec::Vec::as_slice).collect();

    // Resolve the executable's absolute path for /proc/<pid>/exe.  We
    // canonicalise the caller's filename against the process cwd so a
    // relative execve still yields an absolute exe link.  Best-effort:
    // on failure we pass None and the link reports NotFound.
    let exe_path: Option<alloc::vec::Vec<u8>> = {
        let cwd = crate::proc::pcb::get_cwd(pid).unwrap_or_else(|| alloc::vec![b'/']);
        canonicalize_path(&cwd, filename_bytes).ok()
    };

    // ---- 7. Exec.  After this point the old AS is gone on success. ----
    match exec_process(
        pid,
        &elf_data,
        &argv_slices,
        &envp_slices,
        exe_path.as_deref(),
    ) {
        Ok(result) => {
            // Reset caught signal handlers (POSIX) and drop the now-
            // stale signal trampoline; the new image's libc init
            // will re-register.
            signal::on_exec(pid);
            linux_sigaction_on_exec(pid);

            // Rewrite the saved frame so SYSRET lands at the new
            // entry point with a clean register state.
            frame.user_rip = result.entry_rip;
            frame.user_rsp = result.user_rsp;
            frame.arg0 = 0; // rdi
            frame.arg1 = 0; // rsi
            frame.arg2 = 0; // rdx
            frame.arg3 = 0; // r10
            frame.arg4 = 0; // r8
            frame.arg5 = 0; // r9
            frame.rbx = 0;
            frame.rbp = 0;
            frame.r12 = 0;
            frame.r13 = 0;
            frame.r14 = 0;
            frame.r15 = 0;
            // RFLAGS: keep IF=1 (interrupts enabled), reserved bit 1.
            frame.user_rflags = 0x202;
            0
        }
        Err(e) => -i64::from(linux_errno_for(e)),
    }
}

/// `execveat(dirfd, pathname, argv, envp, flags)` — `execve` relative to a
/// directory fd (and the basis of glibc's `fexecve`).
///
/// Real execution is routed here via [`dispatch_linux_with_frame`] because,
/// like `execve`, success rewrites the saved register frame to enter the
/// new image.  This resolves `dirfd` + `pathname` to a VFS-openable path —
/// honouring `AT_EMPTY_PATH` for the `fexecve(fd, …)` form (empty path:
/// exec the file the fd refers to) — then delegates to
/// [`linux_exec_common`].  `AT_SYMLINK_NOFOLLOW` rejects a final symlink
/// component with `ELOOP` (Linux's `do_open_execat` behaviour).
///
/// The non-frame [`sys_execveat`] entry (reachable only via the regular
/// dispatch table, e.g. argument-validation tests) cannot rewrite a frame
/// and so still returns `ENOSYS` after validating its arguments.
fn linux_execveat(frame: &mut crate::syscall::entry::SyscallFrame) -> i64 {
    const AT_EMPTY_PATH: u32 = 0x1000;
    const AT_SYMLINK_NOFOLLOW: u32 = 0x100;

    #[allow(clippy::cast_possible_truncation)]
    let dirfd = frame.arg0 as i32;
    let path_ptr = frame.arg1;
    let argv_user = frame.arg2;
    let envp_user = frame.arg3;
    #[allow(clippy::cast_possible_truncation)]
    let flags = frame.arg4 as u32;

    if flags & !(AT_EMPTY_PATH | AT_SYMLINK_NOFOLLOW) != 0 {
        return -i64::from(errno::EINVAL);
    }

    // Decide whether pathname is empty (NULL pointer or first byte NUL).
    let path_is_empty = if path_ptr == 0 {
        true
    } else {
        let mut first = 0u8;
        // SAFETY: copy_from_user validates the single-byte user read and
        // performs the STAC/CLAC dance for SMAP.
        match unsafe { crate::mm::user::copy_from_user(path_ptr, &raw mut first, 1) } {
            Ok(()) => first == 0,
            Err(e) => return -i64::from(linux_errno_for(e)),
        }
    };

    // Resolve to a VFS-openable path string.
    let filename_string: alloc::string::String = if path_is_empty {
        if flags & AT_EMPTY_PATH == 0 {
            // Empty path without AT_EMPTY_PATH → ENOENT (Linux getname()).
            return -i64::from(errno::ENOENT);
        }
        // fexecve form: exec the file referred to by dirfd.  AT_FDCWD names
        // the cwd (a directory), which is not executable.
        if dirfd == AT_FDCWD {
            return -i64::from(errno::EACCES);
        }
        let entry = match lookup_caller_fd(dirfd) {
            Ok(e) => e,
            Err(sr) => return sr.value,
        };
        if entry.kind != HandleKind::File {
            return -i64::from(errno::EACCES);
        }
        match crate::fs::handle::handle_path(entry.raw_handle) {
            Ok(p) => p,
            Err(e) => return -i64::from(linux_errno_for(e)),
        }
    } else {
        match resolve_at_path(dirfd, path_ptr) {
            Ok(s) => s,
            Err(sr) => return sr.value,
        }
    };

    // AT_SYMLINK_NOFOLLOW: refuse a final symlink component.  Our VFS
    // read_file would transparently follow it, so lstat the resolved path
    // and return ELOOP when it is a symlink, matching Linux.
    if flags & AT_SYMLINK_NOFOLLOW != 0 {
        match crate::fs::Vfs::lstat(&filename_string) {
            Ok(entry) if entry.entry_type == crate::fs::EntryType::Symlink => {
                return -i64::from(errno::ELOOP);
            }
            Ok(_) => {}
            Err(KernelError::NotFound) => return -i64::from(errno::ENOENT),
            Err(e) => return -i64::from(linux_errno_for(e)),
        }
    }

    let filename_bytes = filename_string.as_bytes();
    linux_exec_common(frame, &filename_string, filename_bytes, argv_user, envp_user)
}

