/// `preadv(fd, iov, iovcnt, offset)` — positional vectored read.
///
/// Implemented via [`fs::handle::read_at`](crate::fs::handle::read_at):
/// the file's current offset is **not** modified.  Only File handles
/// support positional I/O; Console / Pipe return `ESPIPE`.
fn sys_preadv(args: &SyscallArgs) -> SyscallResult {
    let fd = args.arg0 as i32;
    let iov_ptr = args.arg1;
    let iovcnt = args.arg2 as i32;
    let offset = args.arg3 as i64;
    if offset < 0 {
        return linux_err(errno::EINVAL);
    }
    if let Err(r) = validate_iov(iov_ptr, iovcnt, false) {
        return r;
    }
    let entry = match lookup_caller_fd(fd) {
        Ok(e) => e,
        Err(r) => return r,
    };
    match entry.kind {
        HandleKind::File => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            preadv_file_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::MemFd => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            preadv_memfd_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::Console | HandleKind::Pipe | HandleKind::EventFd | HandleKind::PidFd | HandleKind::Epoll | HandleKind::SignalFd | HandleKind::Timerfd | HandleKind::Inotify | HandleKind::AlsaPcm | HandleKind::AlsaControl | HandleKind::DrmCard | HandleKind::Socket => linux_err(errno::ESPIPE),
    }
}

/// `pwritev(fd, iov, iovcnt, offset)` — positional vectored write.
fn sys_pwritev(args: &SyscallArgs) -> SyscallResult {
    let fd = args.arg0 as i32;
    let iov_ptr = args.arg1;
    let iovcnt = args.arg2 as i32;
    let offset = args.arg3 as i64;
    if offset < 0 {
        return linux_err(errno::EINVAL);
    }
    if let Err(r) = validate_iov(iov_ptr, iovcnt, true) {
        return r;
    }
    let entry = match lookup_caller_fd(fd) {
        Ok(e) => e,
        Err(r) => return r,
    };
    match entry.kind {
        HandleKind::File => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            pwritev_file_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::MemFd => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            pwritev_memfd_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::Console | HandleKind::Pipe | HandleKind::EventFd | HandleKind::PidFd | HandleKind::Epoll | HandleKind::SignalFd | HandleKind::Timerfd | HandleKind::Inotify | HandleKind::AlsaPcm | HandleKind::AlsaControl | HandleKind::DrmCard | HandleKind::Socket => linux_err(errno::ESPIPE),
    }
}

/// `preadv2(fd, iov, iovcnt, offset, flags)` — like preadv with RWF_* flags.
///
/// flags ⊆ `RWF_SUPPORTED` = { RWF_HIPRI=1 | RWF_DSYNC=2 | RWF_SYNC=4 |
/// RWF_NOWAIT=8 | RWF_APPEND=16 } (= 0x1F) per v6.6
/// `include/uapi/linux/fs.h`.  Bits above APPEND are post-6.6
/// additions and must be rejected with `-EOPNOTSUPP`: RWF_NOAPPEND
/// (0x20, Linux 6.9), RWF_ATOMIC (0x40, Linux 6.11), RWF_DONTCACHE
/// (0x80, Linux 6.14).
/// offset == -1 means "use current file offset" (i.e. behave as
/// `readv`); we dispatch back through `sys_readv` in that case.
///
/// All `RWF_*` flags are accepted but treated as hints (we don't yet
/// have a block layer that can honour them); this matches the
/// behaviour glibc expects — feature-detection probes call preadv2
/// with `RWF_HIPRI=0` and either get success (modern kernel) or
/// ENOSYS (old kernel).  We're "modern" without the perf hints.
fn sys_preadv2(args: &SyscallArgs) -> SyscallResult {
    let fd = args.arg0 as i32;
    let iov_ptr = args.arg1;
    let iovcnt = args.arg2 as i32;
    let offset = args.arg3 as i64;
    let flags = args.arg4 as u32;
    if offset < -1 {
        return linux_err(errno::EINVAL);
    }
    // Batch 525: RWF_SUPPORTED in v6.6 (include/uapi/linux/fs.h) is
    // HIPRI|DSYNC|SYNC|NOWAIT|APPEND = 0x1F.  Pre-batch the mask was
    // 0xFF, accepting RWF_NOAPPEND (0x20, 6.9), RWF_ATOMIC (0x40,
    // 6.11), and RWF_DONTCACHE (0x80, 6.14) — its own comment admitted
    // "kernel ≥ 6.11 maximum bits".  v6.6's kiocb_set_rw_flags returns
    // -EOPNOTSUPP for any bit outside RWF_SUPPORTED.
    const RWF_VALID: u32 = 1 | 2 | 4 | 8 | 16;
    if flags & !RWF_VALID != 0 {
        return linux_err(errno::EOPNOTSUPP);
    }
    if let Err(r) = validate_iov(iov_ptr, iovcnt, false) {
        return r;
    }
    if offset == -1 {
        // preadv2(offset=-1) is defined to use the current file offset,
        // i.e. behave exactly like readv.
        return sys_readv(args);
    }
    let entry = match lookup_caller_fd(fd) {
        Ok(e) => e,
        Err(r) => return r,
    };
    match entry.kind {
        HandleKind::File => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            preadv_file_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::MemFd => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            preadv_memfd_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::Console | HandleKind::Pipe | HandleKind::EventFd | HandleKind::PidFd | HandleKind::Epoll | HandleKind::SignalFd | HandleKind::Timerfd | HandleKind::Inotify | HandleKind::AlsaPcm | HandleKind::AlsaControl | HandleKind::DrmCard | HandleKind::Socket => linux_err(errno::ESPIPE),
    }
}

/// `pwritev2(fd, iov, iovcnt, offset, flags)`.
///
/// `flags` validated against v6.6 `RWF_SUPPORTED` (0x1F) — see
/// `sys_preadv2` for the full per-bit version provenance.
fn sys_pwritev2(args: &SyscallArgs) -> SyscallResult {
    let fd = args.arg0 as i32;
    let iov_ptr = args.arg1;
    let iovcnt = args.arg2 as i32;
    let offset = args.arg3 as i64;
    let flags = args.arg4 as u32;
    if offset < -1 {
        return linux_err(errno::EINVAL);
    }
    // Batch 525: v6.6 RWF_SUPPORTED = 0x1F (was 0xFF, accepting the
    // 6.9/6.11/6.14 RWF bits).  See sys_preadv2.
    const RWF_VALID: u32 = 1 | 2 | 4 | 8 | 16;
    if flags & !RWF_VALID != 0 {
        return linux_err(errno::EOPNOTSUPP);
    }
    if let Err(r) = validate_iov(iov_ptr, iovcnt, true) {
        return r;
    }
    if offset == -1 {
        return sys_writev(args);
    }
    let entry = match lookup_caller_fd(fd) {
        Ok(e) => e,
        Err(r) => return r,
    };
    match entry.kind {
        HandleKind::File => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            pwritev_file_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::MemFd => {
            #[allow(clippy::cast_sign_loss)]
            let off = offset as u64;
            pwritev_memfd_walk(entry.raw_handle, off, iov_ptr, iovcnt)
        }
        HandleKind::Console | HandleKind::Pipe | HandleKind::EventFd | HandleKind::PidFd | HandleKind::Epoll | HandleKind::SignalFd | HandleKind::Timerfd | HandleKind::Inotify | HandleKind::AlsaPcm | HandleKind::AlsaControl | HandleKind::DrmCard | HandleKind::Socket => linux_err(errno::ESPIPE),
    }
}

/// `remap_file_pages(addr, size, prot, pgoff, flags)` — non-linear mapping
/// reshuffle.
///
/// Deprecated since Linux 3.16 in favour of multiple `mmap` calls;
/// glibc dropped its wrapper in 2.x and modern callers use either
/// `mmap(MAP_FIXED)` directly or `mremap`.
///
/// Linux gate order (mm/mmap.c::SYSCALL_DEFINE5(remap_file_pages)):
///
///   SYSCALL_DEFINE5(remap_file_pages, unsigned long, start,
///                   unsigned long, size, unsigned long, prot,
///                   unsigned long, pgoff, unsigned long, flags)
///   {
///       ...
///       if (prot)
///           return ret;          // ret = -EINVAL
///       start = start & PAGE_MASK;
///       size  = size  & PAGE_MASK;
///       if (start + size <= start)
///           return ret;
///       ...
///   }
///
/// Two pre-batch divergences:
///
///   * prot validation was BACKWARDS.  The pre-batch doc-comment
///     ("prot must contain at least one access bit; 0 here would
///     be PROT_NONE which is not what callers want") inverts
///     Linux's contract: Linux REJECTS any non-zero prot, because
///     remap_file_pages preserves the original VMA's protection.
///     Userspace passing PROT_READ (1) saw ENOSYS pre-batch where
///     Linux returns EINVAL, masking the real "use mmap" signal.
///     Post-batch: prot != 0 -> EINVAL.
///
///   * prot was cast to i32, truncating high bits.  Linux's
///     `unsigned long prot` is 64-bit; a caller passing
///     prot = 0x1_0000_0000 truncated to 0 pre-batch (now
///     "accepted") but Linux sees non-zero -> EINVAL.  Compare
///     against args.arg2 directly.
///
/// The addr alignment check is retained as a fidelity-stricter
/// approximation of Linux's `start & PAGE_MASK` round-down: Linux
/// silently rounds misaligned addrs and continues to the VMA
/// lookup (which then EINVALs for missing VMAs), so pre-batch's
/// EINVAL-on-misalignment yields the same errno as Linux's
/// likely terminal in practice.  No probe-observable divergence.
///
/// Batch 390: add the two arithmetic-overflow gates Linux runs
/// after the prot reject and PAGE_MASK rounds:
///
///   * `if (start + size <= start) return ret;` — wraps to
///     EINVAL.  After PAGE_MASK, `size == 0` makes this
///     trivially true so `size=0` is a silent EINVAL (not
///     ENOSYS).  Pre-batch we let `size=0` flow through to
///     ENOSYS, masking the real "bad size" signal.
///
///   * `if (pgoff + (size >> PAGE_SHIFT) < pgoff) return ret;`
///     — pgoff arithmetic wrap-around (huge pgoff + non-trivial
///     size).  Pre-batch we ignored pgoff entirely.
///
/// The PAGE_SHIFT is 14 (16 KiB pages) per CLAUDE.md.  Linux
/// uses 12 (4 KiB), but the LOGIC — overflow check on the file
/// page index sum — is what's faithful.
fn sys_remap_file_pages(args: &SyscallArgs) -> SyscallResult {
    let addr = args.arg0;
    let size = args.arg1;
    let prot = args.arg2;
    let pgoff = args.arg3;
    let _flags = args.arg4;
    // 16 KiB alignment — see CLAUDE.md architectural rules.
    if !addr.is_multiple_of(0x4000) {
        return linux_err(errno::EINVAL);
    }
    // Linux: `if (prot) return -EINVAL;` — any non-zero prot
    // is rejected (the original VMA's protection is preserved).
    if prot != 0 {
        return linux_err(errno::EINVAL);
    }
    // Linux: `start = start & PAGE_MASK; size = size & PAGE_MASK;`
    // then `if (start + size <= start) return -EINVAL;`.  We've
    // already rejected misaligned start so masking start is a
    // no-op; mask size to mirror Linux's behaviour for size that's
    // not a multiple of the page size (low bits silently dropped).
    let size_masked = size & !0x3fffu64; // 16 KiB PAGE_MASK
    // After mask, `start + size_masked <= start` catches:
    //   - size_masked == 0 (including the size=0 case)
    //   - arithmetic wrap-around when start + size overflows
    let end = addr.wrapping_add(size_masked);
    if end <= addr {
        return linux_err(errno::EINVAL);
    }
    // Linux: `if (pgoff + (size >> PAGE_SHIFT) < pgoff) return -EINVAL;`
    // — pgoff arithmetic overflow on the file page index.
    let pages = size_masked >> 14; // 16 KiB PAGE_SHIFT
    if pgoff.wrapping_add(pages) < pgoff {
        return linux_err(errno::EINVAL);
    }
    linux_err(errno::ENOSYS)
}

/// `ioprio_set(which, who, ioprio)` — set I/O scheduling priority.
///
/// which ∈ {IOPRIO_WHO_PROCESS=1, _PGRP=2, _USER=3}.
/// ioprio packs class (top 3 bits, 0..=3 for NONE/RT/BE/IDLE) and
/// data (bottom 13 bits, 0..=7 priority).
///
/// We don't run a per-task I/O scheduler yet (storage I/O is FIFO
/// through the block layer), so the stored value has no scheduling
/// effect — but `ionice -p N -c 1 -n 0 ; ionice -p N` round-trips
/// the value through the per-PCB store so probing utilities see
/// the value they installed (rather than the immutable default the
/// pre-batch stub returned).
///
/// `who` semantics:
///   - `IOPRIO_WHO_PROCESS` (1): `who == 0` -> caller; `who > 0`
///     -> that exact pid (ESRCH if it does not exist).
///   - `IOPRIO_WHO_PGRP` (2) / `_USER` (3): `who == 0` -> caller;
///     `who > 0` -> ESRCH (no pgrp/uid model yet).  Same surface
///     behaviour as Linux returns when no process matches the
///     pgrp/uid; differs from Linux only in that Linux can match
///     when the pgrp/uid happens to have live processes.
///
/// Batch 431 — class/data validation now mirrors Linux's
/// `block/ioprio.c::SYSCALL_DEFINE3(ioprio_set)` gate order:
///
/// ```c
///     int class = IOPRIO_PRIO_CLASS(ioprio);
///     int data  = IOPRIO_PRIO_DATA(ioprio);
///     int ret   = -ESRCH;
///
///     switch (class) {
///     case IOPRIO_CLASS_RT:
///         if (!capable(CAP_SYS_ADMIN) && !capable(CAP_SYS_NICE))
///             return -EPERM;
///         fallthrough;
///     case IOPRIO_CLASS_BE:
///         if (data >= IOPRIO_NR_LEVELS || data < 0)
///             return -EINVAL;
///         break;
///     case IOPRIO_CLASS_IDLE:
///         break;
///     case IOPRIO_CLASS_NONE:
///         if (data)
///             return -EINVAL;
///         break;
///     default:
///         return -EINVAL;
///     }
///
///     switch (which) { ... default: ret = -EINVAL; }
/// ```
///
/// Three observable pre-batch divergences relative to that body:
///
///   * `class = IOPRIO_CLASS_RT, data = 0`           ours: 0      Linux: -EPERM
///   * `class = IOPRIO_CLASS_NONE, data = 5`         ours: 0      Linux: -EINVAL
///   * `class = IOPRIO_CLASS_IDLE, data = 99`        ours: -EINVAL Linux: 0
///
/// And one gate-order divergence (same errno, different precedence
/// when both fail):
///
///   * `which = 99, class = RT, data = 0`            ours: -EINVAL (which gate)
///     Linux: -EPERM (class gate first)
///
/// Why it matters: ionice(1), util-linux's `chrt -i`, fio's `ioprio`
/// option, and systemd's `IOSchedulingClass=` directive all probe
/// the class-switch errno to decide whether to fall back.  A daemon
/// that asks for RT-class IO and sees success on this kernel
/// believes it got privileged scheduling — when in reality the
/// stored value has no effect.  A daemon that asks for NONE-class
/// at data!=0 (an explicit "default class, but please remember the
/// hint" call shape produced by some packagers) used to silently
/// succeed pre-batch, hiding a libc-side bug from the developer.
/// And IDLE-class callers passing high data values (common from
/// shell scripts pulling data out of `/proc/.../io` and re-feeding
/// it) saw EINVAL where Linux ignored the field.
///
/// Architectural directive: this is a translator-only fix.  RT
/// class is uniformly rejected with EPERM because we expose no way
/// for userspace to acquire CAP_SYS_NICE through this ABI (same
/// pattern as sys_settimeofday's CAP_SYS_TIME rejection).  No
/// native API changes, no capability model changes — when a
/// capability model lands, the RT branch becomes a `capable(...)`
/// call instead of an unconditional EPERM.
fn sys_ioprio_set(args: &SyscallArgs) -> SyscallResult {
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let which = args.arg0 as i32;
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let who = args.arg1 as i32;
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let ioprio = args.arg2 as i32;

    let class = (ioprio >> pcb::LINUX_IOPRIO_CLASS_SHIFT) & 0x7;
    let data = ioprio & pcb::LINUX_IOPRIO_DATA_MASK;

    // Linux gate 1: class switch.  Runs BEFORE which-validation.
    // IOPRIO_NR_LEVELS == 8 (data bits 0..=7 are the meaningful
    // priority range; the field is 13 bits wide but Linux rejects
    // anything outside 0..=7 for RT/BE).
    const IOPRIO_NR_LEVELS: i32 = 8;
    match class {
        // RT: Linux checks CAP_SYS_ADMIN || CAP_SYS_NICE.  We
        // expose no way to acquire either through this ABI, so
        // RT is uniformly EPERM.  When a capability model lands
        // this becomes `if (!has_cap(...)) return EPERM;` and the
        // fallthrough to the BE data-range check runs as in Linux.
        c if c == pcb::LINUX_IOPRIO_CLASS_RT => {
            return linux_err(errno::EPERM);
        }
        c if c == pcb::LINUX_IOPRIO_CLASS_BE => {
            if !(0..IOPRIO_NR_LEVELS).contains(&data) {
                return linux_err(errno::EINVAL);
            }
        }
        c if c == pcb::LINUX_IOPRIO_CLASS_IDLE => {
            // data is intentionally ignored — Linux's IDLE arm
            // has no data-range check, the value is stored as-is.
        }
        c if c == pcb::LINUX_IOPRIO_CLASS_NONE => {
            // NONE means "use the scheduler hint", so a non-zero
            // data field is a contradiction: there's no class to
            // attach the data to.
            if data != 0 {
                return linux_err(errno::EINVAL);
            }
        }
        _ => return linux_err(errno::EINVAL),
    }

    // Linux gate 2: which switch.  Default arm -> -EINVAL.
    if !(1..=3).contains(&which) {
        return linux_err(errno::EINVAL);
    }

    let target_pid = match resolve_ioprio_target(which, who) {
        Ok(pid) => pid,
        Err(r) => return r,
    };
    match pcb::set_ioprio(target_pid, ioprio) {
        Some(_) => SyscallResult::ok(0),
        None => linux_err(errno::ESRCH),
    }
}

/// `ioprio_get(which, who)` — read I/O scheduling priority.
///
/// Returns the per-PCB stored value, defaulting to
/// `(IOPRIO_CLASS_BE << 13) | 4` (Linux's documented default
/// for tasks that have not called `ioprio_set`).  Same `who`
/// resolution rules as [`sys_ioprio_set`].
fn sys_ioprio_get(args: &SyscallArgs) -> SyscallResult {
    let which = args.arg0 as i32;
    let who = args.arg1 as i32;
    if !(1..=3).contains(&which) {
        return linux_err(errno::EINVAL);
    }
    let target_pid = match resolve_ioprio_target(which, who) {
        Ok(pid) => pid,
        Err(r) => return r,
    };
    match pcb::get_ioprio(target_pid) {
        Some(v) => SyscallResult::ok(i64::from(v)),
        None => linux_err(errno::ESRCH),
    }
}

/// Resolve the (which, who) pair from `ioprio_set` / `ioprio_get`
/// to a single target pid.  See [`sys_ioprio_set`] for the
/// semantics this enforces.
///
/// `Err(SyscallResult)` is an already-formatted error response
/// (currently always `-ESRCH`).
fn resolve_ioprio_target(which: i32, who: i32) -> Result<u64, SyscallResult> {
    // Linux: which=1 -> who is a tid; we treat it as a pid.
    // which in {2,3} -> who is a pgid / uid; we don't model
    // either yet, so any non-zero who returns ESRCH.
    if who == 0 {
        // Caller's own task.  Kernel context (no PCB) has no
        // ioprio storage; ESRCH matches Linux's behaviour for a
        // pid that does not exist.
        return caller_pid().ok_or_else(|| linux_err(errno::ESRCH));
    }
    if who < 0 {
        // Negative who is invalid for all three "which" values
        // (Linux returns EINVAL for who<0 on _PROCESS; ESRCH on
        // _PGRP because no negative pgid is valid).  We collapse
        // to ESRCH to keep the surface uniform.
        return Err(linux_err(errno::ESRCH));
    }
    match which {
        1 => {
            // IOPRIO_WHO_PROCESS: who is a pid.  Check it exists.
            let target = who as u64;
            if pcb::get_ioprio(target).is_some() {
                Ok(target)
            } else {
                Err(linux_err(errno::ESRCH))
            }
        }
        // No pgrp / uid model yet; non-zero who has nothing to
        // match.
        2 | 3 => Err(linux_err(errno::ESRCH)),
        // Caller already filtered which in 1..=3, so this is
        // unreachable.  Return ESRCH defensively.
        _ => Err(linux_err(errno::ESRCH)),
    }
}

/// `io_pgetevents(ctx_id, min_nr, nr, events*, timeout*, sig*)` —
/// timed/signal-masked variant of `io_getevents`.
///
/// Our io_setup/destroy return ENOSYS so no AIO context can exist;
/// io_pgetevents on a non-existent ctx returns EINVAL.  Validate ptrs
/// for shape, then return EINVAL — mirrors what io_getevents does for
/// an unknown context.
fn sys_io_pgetevents(args: &SyscallArgs) -> SyscallResult {
    // Linux v6.6 fs/aio.c SYSCALL_DEFINE6(io_pgetevents) verbatim order:
    //   if (timeout && get_timespec64(&ts, timeout))     return -EFAULT;
    //   if (usig && copy_from_user(&ksig, usig, 16))      return -EFAULT;
    //   ret = set_user_sigmask(ksig.sigmask, ksig.sigsetsize); if (ret) return ret;
    //   ret = do_io_getevents(ctx_id, min_nr, nr, events, timeout ? &ts : NULL);
    // set_user_sigmask (kernel/signal.c) verbatim order:
    //   if (!umask)                          return 0;    // NULL mask: NO further checks
    //   if (sigsetsize != sizeof(sigset_t))  return -EINVAL;   // 8 on x86_64
    //   if (copy_from_user(&kmask, umask, 8)) return -EFAULT;
    // do_io_getevents -> lookup_ioctx -> -EINVAL (no AIO context ever exists
    //   here, so this is the terminal). The min_nr/nr ordering check and the
    //   events write live in read_events, reached only AFTER a valid ctx, so
    //   they are unreachable on this kernel and collapse into the terminal.
    //
    // Batch 542: the pre-batch order was substantially wrong. It ran the
    // min_nr/nr -> EINVAL check and the `events` write validation FIRST
    // (before even reading `timeout`), and it checked `sigsetsize != 8` even
    // when `sigmask` was NULL. Two real divergences: (a) a probe with
    // (min_nr>nr, timeout=BADPTR) must see EFAULT (get_timespec64 runs first),
    // not EINVAL; (b) a NULL sigmask paired with a bogus sigsetsize must NOT
    // see the sigsetsize EINVAL, because set_user_sigmask early-returns 0 on a
    // NULL mask before touching sigsetsize. Reorder and gate to match Linux.
    let timeout = args.arg4;
    let sig = args.arg5;

    // 1. get_timespec64(timeout): 16-byte copy_from_user -> EFAULT.
    if timeout != 0 {
        if let Err(e) = crate::mm::user::validate_user_read(timeout, 16) {
            return linux_err(linux_errno_for(e));
        }
    }

    // 2. copy_from_user(&ksig, usig, sizeof(__aio_sigset)=16) -> EFAULT, then
    //    set_user_sigmask(ksig.sigmask, ksig.sigsetsize).
    if sig != 0 {
        if let Err(e) = crate::mm::user::validate_user_read(sig, 16) {
            return linux_err(linux_errno_for(e));
        }
        let mut buf = [0u8; 16];
        // SAFETY: validate_user_read above confirmed 16 bytes are readable
        // and aligned to the caller's address space.
        if let Err(e) = unsafe {
            crate::mm::user::copy_from_user(sig, buf.as_mut_ptr(), 16)
        } {
            return linux_err(linux_errno_for(e));
        }
        let sigmask = u64::from_ne_bytes(match <[u8; 8]>::try_from(&buf[0..8]) {
            Ok(b) => b,
            Err(_) => return linux_err(errno::EINVAL),
        });
        let sigsetsize = u64::from_ne_bytes(match <[u8; 8]>::try_from(&buf[8..16]) {
            Ok(b) => b,
            Err(_) => return linux_err(errno::EINVAL),
        });
        // set_user_sigmask: a NULL sigmask short-circuits to success BEFORE the
        // sigsetsize check, so the size gate only applies when sigmask != 0.
        if sigmask != 0 {
            if sigsetsize != 8 {
                return linux_err(errno::EINVAL);
            }
            if let Err(e) = crate::mm::user::validate_user_read(sigmask, 8) {
                return linux_err(linux_errno_for(e));
            }
        }
    }

    // 3. do_io_getevents -> lookup_ioctx fails (no AIO context) -> terminal
    //    EINVAL. The min_nr/nr ordering and events write (read_events) are
    //    unreachable without a valid ctx and collapse into this terminal.
    linux_err(errno::EINVAL)
}

/// `mount_setattr(dirfd, path, flags, attr*, size)` — fsmount-era mount
/// attribute mutation.
///
/// Our mount layer doesn't yet support the new fs-API mutation calls;
/// mount(2) itself is stubbed.  Validate flags, path, and the
/// `struct mount_attr` fields against Linux's gates in
/// `fs/namespace.c::SYSCALL_DEFINE5(mount_setattr)` and
/// `build_mount_kattr()`, then return ENOSYS for the terminal so probes
/// see exactly the same errno layering Linux would give for malformed
/// calls versus "kernel doesn't implement the op."
fn sys_mount_setattr(args: &SyscallArgs) -> SyscallResult {
    let _dirfd = args.arg0 as i32;
    let _path = args.arg1;
    #[allow(clippy::cast_possible_truncation)]
    let flags = args.arg2 as u32;
    let _attr = args.arg3;
    let size = args.arg4;
    // AT_RECURSIVE=0x8000, AT_NO_AUTOMOUNT=0x800, AT_SYMLINK_NOFOLLOW=0x100,
    // AT_EMPTY_PATH=0x1000.
    const VALID: u32 = 0x8000 | 0x800 | 0x100 | 0x1000;
    // Gate 1 (top-level): flag mask EINVAL.  Matches Linux
    // fs/namespace.c::SYSCALL_DEFINE5(mount_setattr) which rejects
    // unknown flag bits before doing anything else.
    if flags & !VALID != 0 {
        return linux_err(errno::EINVAL);
    }
    // Gates 2-4 follow Linux `copy_mount_setattr()` literal statement
    // order (fs/namespace.c):
    //   1. `if (usize > PAGE_SIZE) return -E2BIG;`
    //   2. `if (usize < MOUNT_ATTR_SIZE_VER0) return -EINVAL;`
    //   3. `copy_struct_from_user(...)` — NULL `uattr` surfaces as -EFAULT.
    // Prior to batch 223 we collapsed (attr==NULL || size<VER0) into a
    // single EINVAL gate that preceded the size>PAGE_SIZE check, so:
    //   * (attr=NULL, size=8192) returned EINVAL instead of E2BIG;
    //   * (attr=NULL, size=64) returned EINVAL instead of EFAULT.
    // Use the x86_64 Linux page size (4096) — userspace expects this
    // fixed cap, not our 16 KiB internal frame size.
    const LINUX_PAGE_SIZE: u64 = 4096;
    if size > LINUX_PAGE_SIZE {
        return linux_err(errno::E2BIG);
    }
    // struct mount_attr is 32 bytes (attr_set, attr_clr, propagation, userns_fd) —
    // i.e. MOUNT_ATTR_SIZE_VER0 = 32.
    if size < 32 {
        return linux_err(errno::EINVAL);
    }
    // Batch 493: Linux v6.6 fs/namespace.c::SYSCALL_DEFINE5(mount_setattr)
    // line 4651 runs `if (!may_mount()) return -EPERM;` IMMEDIATELY
    // AFTER the size-VER0 EINVAL gate (line 4648-4649) and BEFORE
    // `copy_struct_from_user(&attr, sizeof(attr), uattr, usize)`
    // (line 4654).  `may_mount()` is `ns_capable(current->nsproxy->
    // mnt_ns->user_ns, CAP_SYS_ADMIN)` (line 1842).
    //
    // Pre-batch we ran (NULL/EFAULT, trailing-zero/E2BIG, attr parse/
    // EINVAL, terminal ENOSYS) all without ever firing EPERM, because
    // this kernel never grants CAP_SYS_ADMIN to Linux-ABI callers
    // (consistent with the architectural directive applied in batches
    // 343 swapoff, 348 acct, 392 fsopen, 393 fsmount, 394 fspick, 492
    // move_mount — all sister `may_mount()`-gated calls).  Multiple
    // observables were Linux-inverted for the unprivileged caller:
    //
    //   * (flags=0, size=32, attr=<zeroed>)            Linux EPERM, ours ENOSYS
    //   * (flags=0, size=64, attr=NULL)                Linux EPERM, ours EFAULT
    //   * (size=32, attr_set=0x400 bad bit)            Linux EPERM, ours EINVAL
    //   * (size=32, attr_clr=0x400 bad bit)            Linux EPERM, ours EINVAL
    //   * (size=32, attr_set=0x30 ATIME conflict)      Linux EPERM, ours EINVAL
    //   * (size=32, attr_set=0x40 undef ATIME bit)     Linux EPERM, ours EINVAL
    //   * (size=32, attr_clr=0x10 without set)         Linux EPERM, ours EINVAL
    //   * (size=32, propagation=MS_SHARED 0x100000)    Linux EPERM, ours ENOSYS
    //   * (size=32, propagation=SHARED|PRIVATE)        Linux EPERM, ours EINVAL
    //   * (size=32, propagation=0xdead bogus)          Linux EPERM, ours EINVAL
    //   * (size=32, attr_set/clr overlap on RDONLY)    Linux EPERM, ours EINVAL
    //   * (size=32, attr_set=RDONLY, clr=NOSUID)       Linux EPERM, ours ENOSYS
    //   * (size=32, userns_fd=5 without IDMAP)         Linux EPERM, ours EINVAL
    //   * (size=32, userns_fd=INT_MAX+1 + IDMAP)       Linux EPERM, ours EINVAL
    //   * (size=32, userns_fd=5 + IDMAP)               Linux EPERM, ours ENOSYS
    //   * (size=32, userns_fd=0 + IDMAP)               Linux EPERM, ours ENOSYS
    //   * (size=40, [32..40)=zeros)                    Linux EPERM, ours ENOSYS
    //   * (size=40, byte[32]=1 trailing non-zero)      Linux EPERM, ours E2BIG
    //
    // All eighteen flip from a mix of EFAULT/EINVAL/E2BIG/ENOSYS to
    // EPERM, matching Linux's gate-4 cutoff for the unprivileged caller.
    // Gates 1-3 (flag mask, size > PAGE_SIZE, size < VER0) remain intact
    // because Linux runs them BEFORE may_mount; their observables are
    // unchanged.
    //
    // Why it matters: mount-attribute mutation tools (`mount -o
    // remount,...` via the new mount API in util-linux 2.39+,
    // systemd's `MountAPIVFS=` with attr-set, OCI runtime `runc`'s
    // ID-mapped mount setup, CRIU's `mount-restore` with kattr
    // replay, container-build tooling like buildah's overlay-mount
    // configuration) all distinguish EPERM ("you need CAP_SYS_ADMIN")
    // from EINVAL ("your kattr is wrong") and ENOSYS ("kernel too
    // old").  Pre-batch our EINVAL/ENOSYS responses led these tools
    // either to log spurious "kattr malformed" diagnostics or to
    // attempt feature-detect retries with reduced attr-set masks
    // that don't fix the underlying privilege problem.
    //
    // Architectural restatement: the diagnostic gates removed below
    // (NULL/EFAULT, trailing-zero/E2BIG, attr_set/clr/propagation/
    // userns_fd validation) are correct for the privileged path
    // they were modelling, but no Linux-ABI caller in this kernel
    // ever holds CAP_SYS_ADMIN.  Their observables are unreachable
    // and were actively misleading by masking the real EPERM signal.
    linux_err(errno::EPERM)
}

/// `fchmodat2(dirfd, path, mode, flags)` — Linux syscall #452.
///
/// ## Linux source — `fs/open.c::do_fchmodat` / `SYSCALL_DEFINE4(fchmodat2)` (v6.6)
///
/// ```c
/// static int do_fchmodat(int dfd, const char __user *filename,
///                        umode_t mode, unsigned int flags)
/// {
///     ...
///     if (unlikely(flags & ~(AT_SYMLINK_NOFOLLOW | AT_EMPTY_PATH)))
///         return -EINVAL;
///     ...
/// }
///
/// SYSCALL_DEFINE4(fchmodat2, int, dfd, const char __user *, filename,
///                 umode_t, mode, unsigned int, flags)
/// {
///     return do_fchmodat(dfd, filename, mode, flags);
/// }
/// ```
///
/// `fchmodat2` is the 4-arg flavor introduced in Linux 6.6: it
/// forwards `flags` to `do_fchmodat`, which validates against
/// `~(AT_SYMLINK_NOFOLLOW | AT_EMPTY_PATH)`.  `flags` is `unsigned
/// int` (low 32 bits only).
///
/// ## Pre-batch divergence (revised by batch 485)
///
/// Pre-batch the routine forwarded to `sys_fchmodat` after a flags
/// gate.  Batch 484 made `sys_fchmodat` call `check_path_str_nonempty`
/// unconditionally — that introduced a regression here: a caller of
/// `fchmodat2(dirfd, "", _, AT_EMPTY_PATH)` would see `-ENOENT`
/// where Linux gives `-EROFS` (the AT_EMPTY_PATH branch operates on
/// `dirfd` directly, not on the pathname).  Batch 485 splits the
/// branches explicitly:
///
/// - `AT_EMPTY_PATH` set: resolve `dirfd` to its backing path
///   (AT_FDCWD → cwd, else an open File fd via `handle_path`), then
///   `chmod_apply`.  Kernel context (no PCB) keeps EROFS.
/// - `AT_EMPTY_PATH` unset: empty path → ENOENT via
///   `check_path_str_nonempty`; kernel context → EROFS; otherwise
///   `resolve_at_path` + `chmod_apply` (real `Vfs::set_permissions`).
fn sys_fchmodat2(args: &SyscallArgs) -> SyscallResult {
    const AT_SYMLINK_NOFOLLOW: u32 = 0x100;
    const AT_EMPTY_PATH: u32 = 0x1000;
    const VALID_FLAGS: u32 = AT_SYMLINK_NOFOLLOW | AT_EMPTY_PATH;

    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let dirfd = args.arg0 as i32;
    let path = args.arg1;
    #[allow(clippy::cast_possible_truncation)]
    let flags = args.arg3 as u32;

    if flags & !VALID_FLAGS != 0 {
        return linux_err(errno::EINVAL);
    }

    if flags & AT_EMPTY_PATH != 0 {
        // AT_EMPTY_PATH: operation targets dirfd directly; path may be
        // empty.  AT_FDCWD targets the cwd; any other dirfd must
        // reference an open File fd.  Same shape as sys_fchownat's
        // AT_EMPTY_PATH branch.  Kernel context (no PCB) keeps EROFS.
        let pid = match caller_pid() {
            Some(p) => p,
            None => return linux_err(errno::EROFS),
        };
        let resolved = if dirfd == AT_FDCWD {
            match pcb::get_cwd(pid).and_then(|c| alloc::string::String::from_utf8(c).ok()) {
                Some(p) => p,
                None => return linux_err(errno::ENOENT),
            }
        } else {
            let entry = match pcb::linux_fd_lookup(pid, dirfd) {
                Some(e) => e,
                None => return linux_err(errno::EBADF),
            };
            if entry.kind != HandleKind::File {
                return linux_err(errno::EINVAL);
            }
            match crate::fs::handle::handle_path(entry.raw_handle) {
                Ok(p) => p,
                Err(e) => return linux_err(linux_errno_for(e)),
            }
        };
        return chmod_apply(&resolved, args.arg2);
    }

    // Non-AT_EMPTY_PATH: empty path → ENOENT (Linux getname empty-path
    // discrimination), then the real chmod for ring-3 callers.
    if let Err(e) = check_path_str_nonempty(path) {
        return linux_err(e);
    }
    if caller_pid().is_none() {
        return linux_err(errno::EROFS);
    }
    let resolved = match resolve_at_path(dirfd, path) {
        Ok(p) => p,
        Err(r) => return r,
    };
    // Fidelity gap: AT_SYMLINK_NOFOLLOW (0x100) is ignored —
    // `Vfs::set_permissions` always follows the final symlink.  See
    // known-issues B-CHOWN1.
    chmod_apply(&resolved, args.arg2)
}

/// `futex_wake(uaddr2*, mask, nr, flags)` — futex2 wake (Linux 6.7+).
///
/// `flags` follows the FUTEX2 layout shared with `futex_wait`:
/// - bits `[0..1]` encode the futex element size (`FUTEX2_SIZE_MASK=0x3`).
///   Only `FUTEX2_SIZE_U32=0x2` is wired; other sizes return `-EINVAL`
///   (matches upstream — Linux only ships U32 today).
/// - bit `2` is `FUTEX2_NUMA=0x4` — NUMA-aware hashing.  We have one
///   global futex hash, so this is `-ENOSYS`.
/// - bit `7` is `FUTEX2_PRIVATE=0x80` — accepted, no per-address-space
///   tagging (we never differentiated private vs shared in the classic
///   futex either).
///
/// `mask == 0` is `-EINVAL`: a zero bitmask can never match any waiter,
/// so Linux rejects it up front.  Our underlying queue does not yet
/// track per-waiter masks, so a non-zero mask wakes any waiter on
/// `uaddr2`; POSIX permits the resulting spurious wakeups (callers
/// re-check their predicate).  When per-waiter mask state is added to
/// `ipc::futex` this becomes a one-line change — same caveat as
/// `FUTEX_WAKE_BITSET` (batch 119).
fn sys_futex2_wake(args: &SyscallArgs) -> SyscallResult {
    const FUTEX2_SIZE_MASK: u32 = 0x3;
    const FUTEX2_SIZE_U32: u32 = 0x2;
    const FUTEX2_NUMA: u32 = 0x4;
    const FUTEX2_PRIVATE: u32 = 0x80;
    const VALID_FLAG_BITS: u32 = FUTEX2_SIZE_MASK | FUTEX2_NUMA | FUTEX2_PRIVATE;

    let uaddr2 = args.arg0;
    let mask = args.arg1;
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let nr = args.arg2 as i32;
    #[allow(clippy::cast_possible_truncation)]
    let flags = args.arg3 as u32;

    // Linux gate order (kernel/futex/syscalls.c:
    // SYSCALL_DEFINE4(futex_wake, void __user *uaddr, unsigned long mask,
    //                 int nr, unsigned int flags)):
    //   1. flags & ~FUTEX2_VALID_MASK            -> -EINVAL
    //   2. !futex_flags_valid(flags)             -> -EINVAL (size != U32)
    //   3. !futex_validate_input(flags, mask)    -> -EINVAL (mask == 0)
    //   4. futex_wake(uaddr, flags, nr, mask):
    //        - get_user_key(uaddr)               -> -EFAULT on bad uaddr
    //        - loop wakes at most `nr` waiters; `nr < 0` is benign and
    //          returns 0 without erroring (the break condition
    //          `++ret >= nr_wake` is immediately true on the first
    //          iteration, and with no waiters the loop body never
    //          runs and `ret` stays 0).
    //
    // Pre-batch we ran:
    //   * uaddr == 0 -> EFAULT                   (FIRST — divergent)
    //   * nr < 0     -> EINVAL                   (divergent: Linux returns 0)
    //   * flag mask  -> EINVAL
    //   * size mask  -> EINVAL
    //   * NUMA flag  -> ENOSYS                   (translator-specific, kept)
    //   * mask == 0  -> EINVAL
    //   * validate_user_read uaddr -> EFAULT
    //   * forward.
    //
    // Concrete divergences:
    //   * futex2_wake(NULL, _, _, 0x100)         Linux: EINVAL (bad flag)
    //                                            Pre:   EFAULT (uaddr first)
    //   * futex2_wake(NULL, _, _, 0)             Linux: EINVAL (size != U32)
    //                                            Pre:   EFAULT
    //   * futex2_wake(NULL, 0, _, F2_SIZE_U32)   Linux: EINVAL (mask == 0)
    //                                            Pre:   EFAULT
    //   * futex2_wake(valid, 1, -1, F2_SIZE_U32) Linux: 0 (benign no-op)
    //                                            Pre:   EINVAL
    //
    // Why this matters: glibc's NPTL pthread_cond_signal path probes
    // futex2 via wake-on-private-mutex and uses EINVAL vs. EFAULT to
    // distinguish "kernel doesn't support futex2 with this flag combo,
    // fall back to FUTEX_WAKE" from "kernel supports futex2 but my
    // address went bad."  EFAULT-on-bad-flags forces the fallback path
    // unnecessarily and bypasses the futex2 fast path forever for that
    // thread.  Similarly, the `nr < 0 -> EINVAL` divergence breaks
    // probes that intentionally pass `nr = -1` as "wake any" - Linux
    // treats this as "wake at most -1 (i.e. wake nothing)" and returns
    // 0, while we returned EINVAL and caused the caller to abort the
    // condvar broadcast loop.
    //
    // Architectural directive: futex semantics are real (we have the
    // ipc::futex backing store).  This is a translator gate-order fix
    // only — no change to the underlying queue.

    // Gate 1: flag mask EINVAL (must come first).
    if flags & !VALID_FLAG_BITS != 0 {
        return linux_err(errno::EINVAL);
    }
    // Gate 2: size != U32 EINVAL.
    if flags & FUTEX2_SIZE_MASK != FUTEX2_SIZE_U32 {
        return linux_err(errno::EINVAL);
    }
    // Gate 2.5: FUTEX2_NUMA — translator-specific.  We have one global
    // futex hash, so a request for NUMA-aware hashing has no truthful
    // answer.  ENOSYS lets glibc's pthread_create + NUMA hint paths
    // detect "kernel doesn't speak NUMA-aware futex2" and fall back to
    // the non-NUMA call.  Linux 6.7+ would accept and ignore on a
    // single-node system; ENOSYS is the closest truthful answer.
    if flags & FUTEX2_NUMA != 0 {
        return linux_err(errno::ENOSYS);
    }
    // Gate 3: mask == 0 EINVAL (futex_validate_input rejects).
    if mask == 0 {
        return linux_err(errno::EINVAL);
    }
    // Gate 4: uaddr validation (in futex_wake() via get_user_key).
    if uaddr2 == 0 {
        return linux_err(errno::EFAULT);
    }
    if let Err(e) = crate::mm::user::validate_user_read(uaddr2, 4) {
        return linux_err(linux_errno_for(e));
    }
    // nr < 0 is benign in Linux — the wake loop breaks before doing
    // anything.  Clamp to 0 so the forwarded handler doesn't surprise
    // us with an unsigned-truncation-induced "wake u32::MAX" instead.
    let nr_clamped: u64 = if nr < 0 { 0 } else { nr as u64 };
    // Forward to the bitset WAKE handler.  arg1 carries `nr` (count to
    // wake), arg2 the wakeup bitset.  The futex2 `mask` is `unsigned long`
    // but a SIZE_U32 futex's per-waiter bitset is 32-bit, so the handler
    // truncates to the low 32 bits (matching Linux's `futex_q.bitset`).
    #[allow(clippy::cast_possible_truncation)]
    let mask_u32 = mask as u32;
    let a = SyscallArgs {
        arg0: uaddr2,
        arg1: nr_clamped,
        arg2: u64::from(mask_u32),
        arg3: 0,
        arg4: 0,
        arg5: 0,
    };
    linux_from_native(handlers::sys_futex_wake_bitset(&a))
}

/// `futex_wait(uaddr*, val, mask, flags, timespec*, clockid)` — futex2 wait (Linux 6.7+).
///
/// Same FUTEX2 flag layout as `sys_futex2_wake`.  `clockid` is
/// restricted to `0` (`CLOCK_MONOTONIC`) and `1` (`CLOCK_REALTIME`);
/// any other clock returns `-EINVAL` per Linux's much tighter check on
/// this path (vs. the 0..=12 range accepted by `clock_gettime`).
/// `timespec == 0` means "wait indefinitely"; otherwise the `timespec`
/// is an **absolute** deadline on the chosen clock — we read it, sample
/// the matching clock, and convert to a relative nanosecond value for
/// `handlers::sys_futex_wait_timeout` (with `saturating_sub` for the
/// "already past" case, which the handler then resolves as
/// value-compare-then-`ETIMEDOUT`).
fn sys_futex2_wait(args: &SyscallArgs) -> SyscallResult {
    const FUTEX2_SIZE_MASK: u32 = 0x3;
    const FUTEX2_SIZE_U32: u32 = 0x2;
    const FUTEX2_NUMA: u32 = 0x4;
    const FUTEX2_PRIVATE: u32 = 0x80;
    const VALID_FLAG_BITS: u32 = FUTEX2_SIZE_MASK | FUTEX2_NUMA | FUTEX2_PRIVATE;

    let uaddr = args.arg0;
    let val = args.arg1;
    let mask = args.arg2;
    #[allow(clippy::cast_possible_truncation)]
    let flags = args.arg3 as u32;
    let timespec = args.arg4;
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let clockid = args.arg5 as i32;

    // Linux gate order (kernel/futex/syscalls.c:
    // SYSCALL_DEFINE6(futex_wait, void __user *, uaddr,
    //                 unsigned long, val, unsigned long, mask,
    //                 unsigned int, flags,
    //                 struct __kernel_timespec __user *, timespec,
    //                 clockid_t, clockid)):
    //   1. clockid validation                   -> -EINVAL
    //   2. flags & ~FUTEX2_VALID_MASK           -> -EINVAL
    //   3. !futex_flags_valid(flags)            -> -EINVAL (size != U32)
    //   4. !futex_validate_input(flags, val)    -> -EINVAL
    //                                              (val truncation for
    //                                               U8/U16; no-op for U32)
    //   5. !futex_validate_input(flags, mask)   -> -EINVAL (ditto)
    //   6. if timespec: get_timespec64(...)     -> -EFAULT
    //                   then timespec64_valid   -> -EINVAL
    //   7. __futex_wait():
    //        - !bitset (i.e. mask == 0)         -> -EINVAL
    //        - get_user(val_now, uaddr)         -> -EFAULT
    //        - compare val_now vs val
    //
    // Pre-batch we ran:
    //   * uaddr == 0 -> EFAULT                  (FIRST — divergent)
    //   * flag mask  -> EINVAL
    //   * size       -> EINVAL
    //   * NUMA       -> ENOSYS                  (translator, kept)
    //   * mask == 0  -> EINVAL                  (too early — Linux
    //                                            checks this inside
    //                                            __futex_wait AFTER
    //                                            timespec)
    //   * clockid    -> EINVAL                  (too late — Linux
    //                                            checks this first)
    //   * validate_user_read uaddr -> EFAULT
    //   * timespec validity -> EINVAL/EFAULT
    //   * forward.
    //
    // Concrete divergences fixed:
    //   * futex2_wait(NULL, _, _, 0x100, _, 0)   Linux: EINVAL
    //                                            Pre:   EFAULT
    //     (the main fix — flag-mask gate now wins over uaddr.)
    //   * futex2_wait(NULL, _, _, 0, _, 0)       Linux: EINVAL
    //                                            Pre:   EFAULT
    //     (size gate now wins over uaddr.)
    //   * futex2_wait(NULL, _, _, F2_U32, _, 99) Linux: EINVAL
    //                                            Pre:   EFAULT
    //     (clockid gate now wins over uaddr.)
    //   * futex2_wait(NULL, _, 0, F2_U32, _, 0)  Linux: EINVAL
    //                                            Pre:   EFAULT
    //     (mask==0 gate now wins over uaddr; even though mask==0
    //      is below timespec in Linux's order, both still beat
    //      uaddr-not-touched-yet.)
    //   * futex2_wait(valid, _, 0, F2_U32, bogus_ts, 0)
    //                                            Linux: EFAULT
    //                                            Pre:   EINVAL
    //     (timespec gate now wins over mask==0; matches Linux's
    //      __futex_wait-after-timespec ordering.)
    //
    // Why this matters: glibc NPTL pthread_cond_wait / sem_timedwait
    // use futex2_wait with a deadline.  When the caller's struct
    // timespec is on a guard page or just past the heap (a common
    // shape under sanitizer-instrumented builds), Linux returns
    // EFAULT and glibc retries with a stack-allocated copy.  Pre-
    // batch we returned EINVAL (the mask==0 fast-path fired before
    // timespec was even read), which glibc interprets as "the
    // kernel rejected my wait params permanently" and aborts the
    // wait, leaving the calling thread spinning on the user-space
    // futex word forever.

    // Gate 1: clockid validation (Linux's first gate).  Allow
    // CLOCK_REALTIME (0) and CLOCK_MONOTONIC (1).  Note Linux casts
    // clockid to `unsigned int` for the check, so negative values
    // wrap to high u32 and miss both, returning -EINVAL — our
    // `clockid != 0 && clockid != 1` on the signed i32 has the
    // same effect (no signed clockid equals 0 or 1 except 0 and 1
    // themselves).
    if clockid != 0 && clockid != 1 {
        return linux_err(errno::EINVAL);
    }
    // Gate 2: flag mask EINVAL.
    if flags & !VALID_FLAG_BITS != 0 {
        return linux_err(errno::EINVAL);
    }
    // Gate 3: size != U32 EINVAL.
    if flags & FUTEX2_SIZE_MASK != FUTEX2_SIZE_U32 {
        return linux_err(errno::EINVAL);
    }
    // Gate 3.5: FUTEX2_NUMA — translator-specific ENOSYS.  See
    // sys_futex2_wake doc comment for the rationale; same one-global-
    // hash limitation.
    if flags & FUTEX2_NUMA != 0 {
        return linux_err(errno::ENOSYS);
    }
    // Gate 4/5: futex_validate_input(flags, val) and (flags, mask).
    // For SIZE_U32 these are unconditionally true (no high-byte
    // truncation possible).  We never wire U8/U16, so nothing to
    // check here — but if/when we do, gate this on
    // `flags & FUTEX2_SIZE_MASK` and reject val/mask >= 1 << (size*8).
    // Gate 6: timespec copy + validity.  Linux's futex2 timespec path
    // runs `get_timespec64()` which copies the 16-byte struct and then
    // `timespec64_valid()` (tv_sec >= 0 AND tv_nsec in [0,
    // NSEC_PER_SEC)).  Use the shared helper for parity with
    // mq_timedsend, mq_timedreceive, semtimedop, etc.
    if timespec != 0 {
        if let Err(r) = validate_user_timespec64(timespec) {
            return r;
        }
    }
    // Gate 7a: mask == 0 (in __futex_wait, AFTER timespec).
    if mask == 0 {
        return linux_err(errno::EINVAL);
    }
    // Gate 7b: uaddr access (in __futex_wait, via get_user).
    if uaddr == 0 {
        return linux_err(errno::EFAULT);
    }
    if let Err(e) = crate::mm::user::validate_user_read(uaddr, 4) {
        return linux_err(linux_errno_for(e));
    }
    // The futex2 `mask` is `unsigned long`; a SIZE_U32 futex's per-waiter
    // bitset is 32-bit, so truncate to the low 32 bits (matching Linux's
    // `futex_q.bitset`).  `mask != 0` was enforced by gate 7a above.
    #[allow(clippy::cast_possible_truncation)]
    let mask_u32 = mask as u32;
    let native = if timespec == 0 {
        // NULL timeout: wait indefinitely.  Bitset in arg2.
        let a = SyscallArgs {
            arg0: uaddr, arg1: val, arg2: u64::from(mask_u32),
            arg3: 0, arg4: 0, arg5: 0,
        };
        handlers::sys_futex_wait_bitset(&a)
    } else {
        let ts = match read_timespec(timespec) {
            Ok(t) => t,
            Err(e) => return linux_err(linux_errno_for(e)),
        };
        let abs_ns = ts.to_nanos();
        let now_ns = if clockid == 1 {
            crate::timekeeping::clock_realtime()
        } else {
            crate::timekeeping::clock_monotonic()
        };
        let rel_ns = abs_ns.saturating_sub(now_ns);
        // Bitset in arg3.
        let a = SyscallArgs {
            arg0: uaddr, arg1: val, arg2: rel_ns,
            arg3: u64::from(mask_u32), arg4: 0, arg5: 0,
        };
        handlers::sys_futex_wait_bitset_timeout(&a)
    };
    linux_from_futex_wait(native)
}

/// `creat(path, mode)` — legacy `open(path, O_CREAT|O_WRONLY|O_TRUNC, mode)`.
///
/// Linux still ships this as a real syscall for backwards-compat with
/// early Unix; in practice glibc's `creat()` libcall is a wrapper for
/// the open path.  We forward to `open_common` so the same EROFS/
/// EFAULT behaviour as `open()` applies.
fn sys_creat(args: &SyscallArgs) -> SyscallResult {
    // O_WRONLY | O_CREAT | O_TRUNC.
    let flags = oflags::O_WRONLY | oflags::O_CREAT | oflags::O_TRUNC;
    open_common(args.arg0, 0, flags)
}

/// `uselib(library)` — deprecated dynamic-linker primitive.
///
/// ## Linux source — `fs/exec.c` (kernel 6.x)
///
/// ```c
/// #ifdef CONFIG_USELIB
/// SYSCALL_DEFINE1(uselib, const char __user *, library)
/// {
///     struct linux_binfmt *fmt;
///     struct file *file;
///     struct filename *tmp = getname(library);
///     int retval = PTR_ERR(tmp);
///     ...
/// }
/// #endif
/// ```
///
/// On modern x86_64 kernels `CONFIG_USELIB=n` is the default (the option
/// was marked obsolete in 5.18; many distros ship it disabled).  With the
/// option disabled, the syscall slot is filled by `sys_ni_syscall` which
/// returns `-ENOSYS` unconditionally without inspecting any argument —
/// the same shape glibc / musl probes expect when feature-testing for
/// `uselib(2)` support.
///
/// ## Divergence (pre-batch → post-batch)
///
/// | Probe              | Linux (CONFIG_USELIB=n) | Pre-batch | Post-batch |
/// |--------------------|-------------------------|-----------|------------|
/// | `uselib(NULL)`     | `ENOSYS`                | `EFAULT`  | `ENOSYS`   |
/// | `uselib(0xDEAD)`   | `ENOSYS`                | `EFAULT`  | `ENOSYS`   |
/// | `uselib(valid)`    | `ENOSYS`                | `ENOSYS`  | `ENOSYS`   |
///
/// ## Why it matters
///
/// glibc removed its `uselib(3)` wrapper in 2.23 (2016), but the kernel
/// slot stayed; LSB-probe suites and a couple of legacy CRT shims still
/// issue `uselib(NULL)` purely as a "is this kernel slot wired up?"
/// feature-probe and branch on `ENOSYS` vs `EFAULT`.  `ENOSYS` ("slot
/// not implemented") makes the probe skip the entire a.out-library path
/// in one step.  `EFAULT` ("you passed me a bad pointer") makes it
/// retry with a real allocated string, only to be told `ENOSYS` on the
/// second try — wasted work and confused diagnostic output.
///
/// ## Architectural directive
///
/// We have no a.out binfmt and no kernel-side library loader (and there
/// never will be — library loading is userspace dynamic-linker territory
/// in a microkernel).  Modelling ourselves as `CONFIG_USELIB=n` is the
/// truthful answer and matches modern desktop Linux defaults.  Pure
/// translator-only fix: drop the pre-ENOSYS pointer gate.
fn sys_uselib(_args: &SyscallArgs) -> SyscallResult {
    linux_err(errno::ENOSYS)
}

/// `sysfs(option, ...)` — deprecated filesystem-type enumeration.
///
/// Linux source: `fs/filesystems.c::SYSCALL_DEFINE3(sysfs)`:
///
/// ```c
/// SYSCALL_DEFINE3(sysfs, int, option, unsigned long, arg1,
///                 unsigned long, arg2)
/// {
///     int retval = -EINVAL;
///     switch (option) {
///     case 1: retval = fs_index((const char __user *)arg1);   break;
///     case 2: retval = fs_name(arg1, (char __user *)arg2);    break;
///     case 3: retval = fs_maxindex();                         break;
///     }
///     return retval;
/// }
/// ```
///
/// Pre-batch (374) we returned ENOSYS for every valid option.  This is
/// the wrong shape: sysfs(2) was never removed, glibc still ships a
/// `sysfs(3)` wrapper, and uClibc / musl probes rely on the count form
/// (`option=3`) to enumerate the kernel's mounted-fs registry without
/// parsing `/proc/filesystems`.  The Linux-faithful answers for a
/// kernel with zero filesystems registered through this legacy table
/// are:
///
///   * option=1 (fs_index, lookup-by-name):
///     getname(arg1) first → EFAULT for NULL/bad ptr.
///     Empty registry → no strcmp match → `err = -EINVAL` at the
///     trailing `read_unlock; putname; return err;`.  Note that
///     fs_index returns EINVAL for "not found", NOT ENOENT.
///   * option=2 (fs_name, lookup-by-index):
///     Walks file_systems list `arg1` times; `!tmp` after the walk
///     (index out of range — always, since the list is empty) sets
///     `res = -EINVAL` BEFORE the copy_to_user call.  Therefore
///     sysfs(2) NEVER touches the output buffer when the index is
///     out of range — no EFAULT can be returned by this path in our
///     environment.
///   * option=3 (fs_maxindex):
///     Returns the count of registered filesystems as a non-negative
///     integer.  Zero registered → 0.  No userspace touch.
///   * any other option:
///     `retval = -EINVAL` initializer is never overwritten → EINVAL.
///
/// The most important divergence is option=3 returning ENOSYS pre-
/// batch: a userspace caller probing for "how many filesystems does
/// this kernel know" was being told the syscall didn't exist when in
/// fact the Linux-shaped answer is "zero filesystems are registered."
/// That misreports kernel capability and pushes the caller through a
/// fallback path (parsing /proc/filesystems) that we don't expose
/// either.
fn sys_sysfs(args: &SyscallArgs) -> SyscallResult {
    // Linux signature: `SYSCALL_DEFINE3(sysfs, int, option, ...)`.
    // `option` is `int` so the x86_64 syscall ABI truncates to its low
    // 32 bits before the body runs.
    #[allow(clippy::cast_possible_truncation, clippy::cast_possible_wrap)]
    let option = args.arg0 as i32;
    match option {
        1 => {
            // fs_index(name): getname(arg1) → EFAULT/ENAMETOOLONG.
            // After getname succeeds, the empty-registry scan falls
            // through to the trailing `err = -EINVAL`.
            if args.arg1 == 0 {
                return linux_err(errno::EFAULT);
            }
            if let Err(e) = validate_user_str(args.arg1) {
                return linux_err(linux_errno_for(e));
            }
            linux_err(errno::EINVAL)
        }
        2 => {
            // fs_name(index, buf): empty list → `!tmp` → -EINVAL with
            // NO copy_to_user touch.  Output buffer ptr is irrelevant.
            linux_err(errno::EINVAL)
        }
        3 => {
            // fs_maxindex(): zero filesystems registered → 0.
            SyscallResult::ok(0)
        }
        _ => linux_err(errno::EINVAL),
    }
}

/// `vhangup()` — privileged TTY hangup (init / getty reset).
///
/// Always requires CAP_SYS_TTY_CONFIG which we don't expose.
fn sys_vhangup(_args: &SyscallArgs) -> SyscallResult {
    linux_err(errno::EPERM)
}

/// `_sysctl(struct __sysctl_args *)` — removed in Linux 5.5 (2020).
///
/// ## Linux source — `kernel/sysctl.c` (kernel 5.5 — 6.x)
///
/// ```c
/// SYSCALL_DEFINE1(_sysctl, struct __sysctl_args __user *, args)
/// {
///     pr_warn_once("warning: process `%s' used the deprecated sysctl "
///              "system call with ", current->comm);
///     return -ENOSYS;
/// }
/// ```
///
/// The `args` argument is referenced ONLY for the once-per-boot warning
/// log; it is never dereferenced and the return code is the literal
/// `-ENOSYS` regardless of pointer validity.
///
/// ## Divergence (pre-batch → post-batch)
///
/// | Probe                    | Linux    | Pre-batch | Post-batch |
/// |--------------------------|----------|-----------|------------|
/// | `_sysctl(NULL)`          | `ENOSYS` | `EFAULT`  | `ENOSYS`   |
/// | `_sysctl(0xDEAD)`        | `ENOSYS` | `EFAULT`  | `ENOSYS`   |
/// | `_sysctl(valid_struct)`  | `ENOSYS` | `ENOSYS`  | `ENOSYS`   |
///
/// ## Why it matters
///
/// glibc 2.32+ removed the `sysctl(3)` wrapper but kept the syscall
/// number for ABI stability; a few stale LSB-test suites and old
/// monitoring agents (collectd's `kernel/sysctl` shim) still issue
/// `_sysctl(NULL)` as a one-shot probe to discriminate "removed"
/// (`ENOSYS`) from "wrong argument shape" (`EFAULT`).  Pre-batch's
/// `EFAULT` made them assume the syscall still exists but they had
/// the struct layout wrong, and they retry with a freshly-allocated
/// `__sysctl_args` — only to see `ENOSYS` on the second attempt.
/// `ENOSYS` on the first attempt skips the whole retry path.
///
/// ## Architectural directive
///
/// Pure translator-only fix: Linux removed sysctl(2) five years ago
/// (Apr 2020) and emits `-ENOSYS` unconditionally; we already had the
/// terminal `ENOSYS` but ran a spurious pointer gate before it.  Drop
/// the gate.  All sysctl-style tunables live under `/proc/sys` (or
/// the orchestrator's config system in our model) — no struct ever
/// crosses the syscall boundary.
#[allow(non_snake_case)]
fn sys__sysctl(_args: &SyscallArgs) -> SyscallResult {
    linux_err(errno::ENOSYS)
}

