        // Per-segment cmd: segment lookup fails with EINVAL before
        // buf is touched, so even a valid buf yields EINVAL.
        let a = SyscallArgs { arg0: 0, arg1: 2, arg2: buf_addr,
            arg3: 0, arg4: 0, arg5: 0 };
